const App: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [status, setStatus] = useState(UI_STRINGS.READY);
  const [history, setHistory] = useState<ChatTurn[]>([]);
  const [error, setError] = useState<string | null>(null);

  const sessionRef = useRef<any>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const transcriptRef = useRef({ user: '', model: '' });

  const stopAllAudio = useCallback(() => {
    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
  }, []);

  const connectSession = async () => {
    if (sessionRef.current) return;

    setError(null);
    setStatus(UI_STRINGS.CONNECTING);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      inputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_INPUT });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_OUTPUT });

      const outputNode = outputContextRef.current.createGain();
      outputNode.connect(outputContextRef.current.destination);

      const sessionPromise = ai.live.connect({
        model: GEMINI_MODEL_NAME,
        callbacks: {
          onopen: () => {
            setStatus(UI_STRINGS.LISTENING);
            setIsActive(true);

            const source = inputContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle Transcriptions
            if (message.serverContent?.outputTranscription) {
              transcriptRef.current.model += message.serverContent.outputTranscription.text;
            } else if (message.serverContent?.inputTranscription) {
              transcriptRef.current.user += message.serverContent.inputTranscription.text;
            }

            if (message.serverContent?.turnComplete) {
              const userText = transcriptRef.current.user;
              const modelText = transcriptRef.current.model;
              if (userText || modelText) {
                setHistory(prev => [
                  ...prev,
                  { id: Date.now() + '-u', role: 'user', text: userText, timestamp: Date.now() },
                  { id: Date.now() + '-m', role: 'model', text: modelText, timestamp: Date.now() }
                ].slice(-10));
              }
              transcriptRef.current = { user: '', model: '' };
            }

            // Handle Audio
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputContextRef.current) {
              setStatus(UI_STRINGS.SPEAKING);
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputContextRef.current.currentTime);

              const buffer = await decodeAudioData(decode(audioData), outputContextRef.current, AUDIO_SAMPLE_RATE_OUTPUT, 1);
              const source = outputContextRef.current.createBufferSource();
              source.buffer = buffer;
              source.connect(outputNode);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setStatus(UI_STRINGS.LISTENING);
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              stopAllAudio();
              setStatus(UI_STRINGS.LISTENING);
            }
          },
          onerror: (e) => {
            console.error("Live API Error:", e);
            setError("Connection error. Try restarting.");
            disconnect();
          },
          onclose: () => {
            disconnect();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction: 'You are a warm, helpful, and high-energy AI companion. Keep your responses conversational and brief to allow for natural back-and-forth flow. Use your expressive voice to show personality.',
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error(err);
      setError(err.message || UI_STRINGS.ERROR_MIC_PERMISSION);
      setStatus(UI_STRINGS.READY);
    }
  };

  const disconnect = () => {
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch (e) {}
      sessionRef.current = null;
    }
    if (inputContextRef.current) {
      inputContextRef.current.close();
      inputContextRef.current = null;
    }
    if (outputContextRef.current) {
      outputContextRef.current.close();
      outputContextRef.current = null;
    }
    stopAllAudio();
    setIsActive(false);
    setStatus(UI_STRINGS.READY);
  };

  const toggleSession = () => {
    if (isActive) disconnect();
    else connectSession();
  };

  return (
    <div className="flex flex-col h-screen bg-[#050505] text-white overflow-hidden font-sans">
      {/* Dynamic Background Effect */}
      <div className="fixed inset-0 pointer-events-none opacity-20">
        <div className={`absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] rounded-full blur-[120px] transition-colors duration-1000 ${isActive ? (status === UI_STRINGS.SPEAKING ? 'bg-purple-600' : 'bg-blue-600') : 'bg-gray-800'}`}></div>
      </div>

      <header className="relative z-10 p-6 flex justify-between items-center border-b border-white/5 backdrop-blur-md">
        <div className="flex items-center gap-3">
          <div className={`w-3 h-3 rounded-full ${isActive ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`}></div>
          <h1 className="text-xl font-medium tracking-tight opacity-90">Gemini Live</h1>
        </div>
        <div className="text-sm font-mono opacity-50 uppercase tracking-widest">{status}</div>
      </header>

      <main className="relative z-10 flex-grow flex flex-col items-center justify-center p-6">
        {/* Visualizer Orb */}
        <div className="relative mb-12">
           <div className={`w-48 h-48 rounded-full flex items-center justify-center transition-all duration-500 border-2 ${isActive ? 'border-white/20 scale-110 shadow-[0_0_80px_rgba(59,130,246,0.2)]' : 'border-white/5 scale-100'}`}>
              {isActive ? (
                <div className="flex items-end gap-1 h-12">
                   {[...Array(5)].map((_, i) => (
                     <div key={i} className={`w-1.5 bg-white rounded-full transition-all duration-150 ${status === UI_STRINGS.SPEAKING ? 'animate-[bounce_0.6s_infinite_ease-in-out]' : 'h-2'}`} style={{ animationDelay: `${i * 0.1}s`, height: status === UI_STRINGS.SPEAKING ? '100%' : '8px' }}></div>
                   ))}
                </div>
              ) : (
                <PowerIcon className="w-16 h-16 opacity-10" />
              )}
           </div>
        </div>

        {/* Live Transcripts */}
        <div className="w-full max-w-lg space-y-4">
          {history.length === 0 && !isActive && (
            <p className="text-center text-white/30 italic">Tap the button below to start a real-time voice conversation.</p>
          )}
          {history.map((turn) => (
            <div key={turn.id} className={`flex flex-col ${turn.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-2 duration-500`}>
              <div className={`px-4 py-2 rounded-2xl max-w-[85%] text-sm ${turn.role === 'user' ? 'bg-white/10 text-white/90' : 'bg-blue-600/20 text-blue-200 border border-blue-500/20'}`}>
                {turn.text || <span className="opacity-20 italic">Listening...</span>}
              </div>
            </div>
          ))}
        </div>
      </main>

      <footer className="relative z-10 p-12 flex flex-col items-center gap-6">
        {error && (
          <div className="bg-red-500/20 text-red-400 px-4 py-2 rounded-full text-xs border border-red-500/30 animate-shake">
            {error}
          </div>
        )}

        <button
          onClick={toggleSession}
          className={`group relative w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 transform hover:scale-105 active:scale-95 ${isActive ? 'bg-red-500 shadow-[0_0_30px_rgba(239,68,68,0.4)]' : 'bg-white shadow-[0_0_30px_rgba(255,255,255,0.2)]'}`}
        >
          {status === UI_STRINGS.CONNECTING ? (
            <Spinner size="md" color="text-black" />
          ) : isActive ? (
            <div className="w-6 h-6 bg-white rounded-sm"></div>
          ) : (
            <MicIcon className="w-8 h-8 text-black" />
          )}

          {/* Label Helper */}
          <span className="absolute -top-10 left-1/2 -translate-x-1/2 whitespace-nowrap text-[10px] font-bold tracking-[0.2em] uppercase opacity-0 group-hover:opacity-100 transition-opacity duration-300">
            {isActive ? 'Disconnect' : 'Connect'}
          </span>
        </button>
      </footer>
    </div>
  );
};

export default App;

