        <div className="relative mb-12">
           <div className={`w-48 h-48 rounded-full flex items-center justify-center transition-all duration-500 border-2 ${isActive ? 'border-white/20 scale-110 shadow-[0_0_80px_rgba(59,130,246,0.2)]' : 'border-white/5 scale-100'}`}>
              {isActive ? (
                <div className="flex items-end gap-1 h-12">
                   {[...Array(5)].map((_, i) => (
                     <div key={i} className={`w-1.5 bg-white rounded-full transition-all duration-150 ${status === UI_STRINGS.SPEAKING ? 'animate-[bounce_0.6s_infinite_ease-in-out]' : 'h-2'}`} style={{ animationDelay: `${i * 0.1}s`, height: status === UI_STRINGS.SPEAKING ? '100%' : '8px' }}></div>
                   ))}
