                </div>
                <div>
                  <label className="block text-xs font-bold uppercase tracking-widest text-white/40 mb-2">Change Admin Key (Optional)</label>
                  <input 
                    type="text"
                    value={newAdminKey}
                    onChange={(e) => setNewAdminKey(e.target.value)}
                    placeholder="Leave blank to keep current..."
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-blue-500/50 transition-colors text-sm"
