const DEFAULT_SYSTEM_INSTRUCTION = 'You are a warm, helpful, and high-energy AI companion. Keep your responses conversational and brief to allow for natural back-and-forth flow. Use your expressive voice to show personality.';

const App: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [status, setStatus] = useState(UI_STRINGS.READY);
  const [history, setHistory] = useState<ChatTurn[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Admin States
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
