      {/* Header */}
      <header className="relative z-40 p-6 flex justify-between items-center backdrop-blur-lg bg-black/10">
        <div className="flex items-center gap-3 group">
          <div className={`w-2 h-2 rounded-full transition-all duration-500 ${isActive ? 'bg-blue-400 shadow-[0_0_10px_rgba(96,165,250,0.8)]' : 'bg-white/20'}`} />
          <h1 className="text-sm font-bold tracking-[0.2em] uppercase opacity-70 group-hover:opacity-100 transition-opacity">Gemini Live</h1>
        </div>

        <button 
          onClick={() => setIsAdminOpen(true)}
          className="p-3 rounded-full hover:bg-white/5 transition-all opacity-30 hover:opacity-100 border border-transparent hover:border-white/10"
        >
          <SettingsIcon className="w-5 h-5" />
        </button>
      </header>

      {/* Main Experience Area */}
      <main className="relative z-20 flex-grow flex flex-col items-center justify-center pt-20">

        {/* THE ORB - Dynamic Visualizer */}
        <div className="relative group flex items-center justify-center w-full max-w-xl aspect-square">

          {/* Inner Fluid Orb Layers */}
          <div className="relative w-64 h-64 md:w-80 md:h-80 flex items-center justify-center">

            {/* Layer 1: Base Glow */}
            <div className={`absolute inset-0 rounded-full blur-2xl transition-all duration-700 mix-blend-screen opacity-60 ${
              isActive ? (status === UI_STRINGS.SPEAKING ? 'bg-purple-500 scale-110' : 'bg-blue-500 scale-105') : 'bg-white/10 scale-95'
            }`} />

            {/* Layer 2: Core */}
            <div className={`absolute w-full h-full rounded-full transition-all duration-500 border border-white/10 ${
              isActive 
                ? 'bg-gradient-to-br from-blue-400/20 via-transparent to-purple-600/20 backdrop-blur-3xl shadow-[0_0_100px_rgba(59,130,246,0.15)]' 
                : 'bg-white/5 border-white/5'
            }`} />

            {/* Layer 3: Dynamic Ripples (CSS Only) */}
            {isActive && (
              <>
                <div className={`absolute inset-0 rounded-full border-2 border-white/5 animate-[ping_3s_linear_infinite] ${status === UI_STRINGS.SPEAKING ? 'opacity-30' : 'opacity-10'}`} />
                <div className={`absolute inset-4 rounded-full border border-white/10 animate-[pulse_2s_ease-in-out_infinite]`} />
              </>
            )}

            {/* Center Content / Bars */}
            <div className="z-30 flex items-center justify-center gap-1.5 h-16">
              {isActive ? (
                [...Array(6)].map((_, i) => (
                  <div 
                    key={i} 
                    className={`w-1 rounded-full transition-all duration-300 ${status === UI_STRINGS.SPEAKING ? 'bg-white shadow-[0_0_15px_white]' : 'bg-blue-300/60'}`} 
                    style={{ 
                      height: isActive ? '100%' : '4px',
                      animation: status === UI_STRINGS.SPEAKING ? `orb-bar 0.8s ease-in-out infinite` : 'none',
                      animationDelay: `${i * 0.1}s`,
                      maxHeight: status === UI_STRINGS.SPEAKING ? '60px' : '8px'
