const DEFAULT_SYSTEM_INSTRUCTION = 'You are a warm, emotionally intelligent, and high-energy AI companion. For EVERY turn, analyze the users voice for emotional subtext and prosody. At the START of your response, identify the users top 3 emotions in this format: [USER_EMOTIONS: Emotion1: 0.xx, Emotion2: 0.xx, Emotion3: 0.xx]. Then provide your actual response. Use your expressive voice to match or complement their state.';

const App: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [status, setStatus] = useState(UI_STRINGS.READY);
  const [history, setHistory] = useState<ChatTurn[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Admin States
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [adminKeyInput, setAdminKeyInput] = useState('');
  const [systemInstruction, setSystemInstruction] = useState(localStorage.getItem('gemini_admin_prompt') || DEFAULT_SYSTEM_INSTRUCTION);
  const [storedAdminKey, setStoredAdminKey] = useState(localStorage.getItem('gemini_admin_key') || 'admin123');
  const [newAdminKey, setNewAdminKey] = useState('');

  // Emotion Analysis States
  const [userEmotions, setUserEmotions] = useState<Emotion[]>([]);

  const sessionRef = useRef<any>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const transcriptRef = useRef({ user: '', model: '', rawModel: '' });

  const stopAllAudio = useCallback(() => {
    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
  }, []);

  const parseEmotions = (text: string) => {
    const match = text.match(/\[USER_EMOTIONS:\s*(.*?)\]/);
    if (match) {
      const emotionPairs = match[1].split(',').map(pair => {
        const [name, scoreStr] = pair.split(':').map(s => s.trim());
        return { name, score: parseFloat(scoreStr) || 0 };
      });
      return emotionPairs;
    }
    return null;
  };

  const connectSession = async () => {
    if (sessionRef.current) return;

    setError(null);
    setStatus(UI_STRINGS.CONNECTING);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      inputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_INPUT });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_OUTPUT });

      const outputNode = outputContextRef.current.createGain();
      outputNode.connect(outputContextRef.current.destination);

      const sessionPromise = ai.live.connect({
        model: GEMINI_MODEL_NAME,
        callbacks: {
          onopen: () => {
            setStatus(UI_STRINGS.LISTENING);
            setIsActive(true);

            const source = inputContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              transcriptRef.current.rawModel += text;

              // Strip emotion tag from the display text
              const cleanedText = transcriptRef.current.rawModel.replace(/\[USER_EMOTIONS:.*?\]/g, '').trim();
              transcriptRef.current.model = cleanedText;

              // Extract emotions if available
              const emotions = parseEmotions(transcriptRef.current.rawModel);
              if (emotions) {
                setUserEmotions(emotions);
              }
            } else if (message.serverContent?.inputTranscription) {
              transcriptRef.current.user += message.serverContent.inputTranscription.text;
            }

            if (message.serverContent?.turnComplete) {
              const userText = transcriptRef.current.user;
              const modelText = transcriptRef.current.model;
              if (userText || modelText) {
                setHistory(prev => [
                  ...prev,
                  { id: Date.now() + '-u', role: 'user', text: userText, timestamp: Date.now() },
                  { id: Date.now() + '-m', role: 'model', text: modelText, timestamp: Date.now() }
                ].slice(-10));
              }
              transcriptRef.current = { user: '', model: '', rawModel: '' };
            }

            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputContextRef.current) {
              setStatus(UI_STRINGS.SPEAKING);
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputContextRef.current.currentTime);

              const buffer = await decodeAudioData(decode(audioData), outputContextRef.current, AUDIO_SAMPLE_RATE_OUTPUT, 1);
              const source = outputContextRef.current.createBufferSource();
              source.buffer = buffer;
              source.connect(outputNode);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setStatus(UI_STRINGS.LISTENING);
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              stopAllAudio();
              setStatus(UI_STRINGS.LISTENING);
            }
          },
          onerror: (e) => {
            console.error("Live API Error:", e);
            setError("Connection error. Try restarting.");
            disconnect();
          },
          onclose: () => {
            disconnect();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction: systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error(err);
      setError(err.message || UI_STRINGS.ERROR_MIC_PERMISSION);
      setStatus(UI_STRINGS.READY);
    }
  };

  const disconnect = () => {
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch (e) {}
      sessionRef.current = null;
    }
    if (inputContextRef.current) {
      inputContextRef.current.close();
      inputContextRef.current = null;
    }
    if (outputContextRef.current) {
      outputContextRef.current.close();
      outputContextRef.current = null;
    }
    stopAllAudio();
    setIsActive(false);
    setUserEmotions([]);
    setStatus(UI_STRINGS.READY);
  };

  const toggleSession = () => {
    if (isActive) disconnect();
    else connectSession();
  };

  const handleAdminAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminKeyInput === storedAdminKey) {
      setIsAdminAuthenticated(true);
      setError(null);
    } else {
      setError("Incorrect Admin Key");
    }
  };

  const saveAdminSettings = () => {
    localStorage.setItem('gemini_admin_prompt', systemInstruction);
    if (newAdminKey) {
      localStorage.setItem('gemini_admin_key', newAdminKey);
      setStoredAdminKey(newAdminKey);
      setNewAdminKey('');
    }
    setIsAdminOpen(false);
    setIsAdminAuthenticated(false);
    setAdminKeyInput('');
    if (isActive) {
      disconnect();
      setTimeout(connectSession, 500);
    }
  };

  // Determine dominant emotion color
  const orbGlowColor = useMemo(() => {
    if (userEmotions.length === 0) return 'rgba(59,130,246,0.3)';
    const top = userEmotions[0];
    const name = top.name.toLowerCase();
    if (name.includes('joy') || name.includes('happy')) return 'rgba(234,179,8,0.5)'; // Yellow
    if (name.includes('anger') || name.includes('mad')) return 'rgba(239,68,68,0.5)'; // Red
    if (name.includes('sad')) return 'rgba(37,99,235,0.5)'; // Blue
    if (name.includes('fear') || name.includes('anxiety')) return 'rgba(147,51,234,0.5)'; // Purple
    if (name.includes('calm') || name.includes('peace')) return 'rgba(34,197,94,0.5)'; // Green
    return 'rgba(59,130,246,0.4)';
  }, [userEmotions]);

  return (
    <div className="relative flex flex-col h-screen bg-[#020202] text-white overflow-hidden font-sans selection:bg-blue-500/30">

      {/* Immersive Background Atmos */}
      <div className="fixed inset-0 pointer-events-none transition-all duration-1000 ease-in-out">
        <div 
          className={`absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[120vw] h-[120vw] rounded-full blur-[180px] transition-all duration-1000 ${
            isActive ? 'opacity-100 scale-110' : 'opacity-20 scale-90'
          }`}
          style={{ backgroundColor: orbGlowColor }}
        />
      </div>

      {/* Header */}
      <header className="relative z-40 p-6 flex justify-between items-center backdrop-blur-lg bg-black/10">
        <div className="flex items-center gap-3 group">
          <div className={`w-2 h-2 rounded-full transition-all duration-500 ${isActive ? 'bg-blue-400 shadow-[0_0_10px_rgba(96,165,250,0.8)]' : 'bg-white/20'}`} />
          <h1 className="text-sm font-bold tracking-[0.2em] uppercase opacity-70 group-hover:opacity-100 transition-opacity">Gemini Live</h1>
        </div>

        <button 
          onClick={() => setIsAdminOpen(true)}
          className="p-3 rounded-full hover:bg-white/5 transition-all opacity-30 hover:opacity-100 border border-transparent hover:border-white/10"
        >
          <SettingsIcon className="w-5 h-5" />
        </button>
      </header>

      {/* Main Experience Area */}
      <main className="relative z-20 flex-grow flex flex-col items-center justify-center pt-20">

        {/* Prosody Analysis Radar (Hume Style) */}
        {isActive && userEmotions.length > 0 && (
          <div className="absolute top-10 right-10 flex flex-col items-end gap-2 animate-in fade-in slide-in-from-right-4 duration-700">
            <span className="text-[10px] font-black tracking-widest uppercase opacity-40 mb-2">Prosody Monitor</span>
            {userEmotions.map((emotion, idx) => (
              <div key={idx} className="flex items-center gap-3 w-48">
                <span className="text-[10px] font-bold uppercase opacity-60 w-20 text-right truncate">{emotion.name}</span>
                <div className="flex-grow h-1.5 bg-white/5 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-white transition-all duration-1000 ease-out"
                    style={{ 
                      width: `${emotion.score * 100}%`,
                      opacity: Math.max(0.2, emotion.score),
                      backgroundColor: orbGlowColor
                    }}
                  />
                </div>
              </div>
            ))}
          </div>
        )}

        {/* THE ORB - Dynamic Visualizer */}
        <div className="relative group flex items-center justify-center w-full max-w-xl aspect-square">

          <div className="relative w-64 h-64 md:w-80 md:h-80 flex items-center justify-center">

            {/* Layer 1: Base Glow */}
            <div className={`absolute inset-0 rounded-full blur-2xl transition-all duration-700 mix-blend-screen opacity-60 scale-105`}
                 style={{ backgroundColor: orbGlowColor }} />

            {/* Layer 2: Core */}
            <div className={`absolute w-full h-full rounded-full transition-all duration-500 border border-white/10 ${
              isActive 
                ? 'bg-gradient-to-br from-white/10 via-transparent to-white/5 backdrop-blur-3xl shadow-[0_0_100px_rgba(255,255,255,0.1)]' 
                : 'bg-white/5 border-white/5'
            }`} />

            {/* Layer 3: Dynamic Ripples (CSS Only) */}
            {isActive && (
              <>
                <div className={`absolute inset-0 rounded-full border-2 border-white/5 animate-[ping_3s_linear_infinite] opacity-20`} />
                <div className={`absolute inset-4 rounded-full border border-white/10 animate-[pulse_2s_ease-in-out_infinite]`} />
              </>
            )}

            {/* Center Content / Bars */}
            <div className="z-30 flex items-center justify-center gap-1.5 h-16">
              {isActive ? (
                [...Array(6)].map((_, i) => (
                  <div 
                    key={i} 
                    className={`w-1 rounded-full transition-all duration-300 ${status === UI_STRINGS.SPEAKING ? 'bg-white shadow-[0_0_15px_white]' : 'bg-blue-300/60'}`} 
                    style={{ 
                      height: isActive ? '100%' : '4px',
                      animation: status === UI_STRINGS.SPEAKING ? `orb-bar 0.8s ease-in-out infinite` : 'none',
                      animationDelay: `${i * 0.1}s`,
                      maxHeight: status === UI_STRINGS.SPEAKING ? '60px' : '8px'
                    }} 
                  />
                ))
