          ))}
        </div>
      </main>

      {/* Primary Interaction Button */}
      <footer className="relative z-30 p-12 flex flex-col items-center justify-end pb-20">
        <button
          onClick={toggleSession}
          className={`group relative w-24 h-24 rounded-full flex items-center justify-center transition-all duration-500 transform hover:scale-105 active:scale-95 border-4 ${
            isActive 
              ? 'bg-red-500/10 border-red-500/50 shadow-[0_0_50px_rgba(239,68,68,0.3)]' 
              : 'bg-white/10 border-white/20 hover:border-white/40 shadow-[0_0_40px_rgba(255,255,255,0.05)]'
          }`}
        >
          {status === UI_STRINGS.CONNECTING ? (
            <Spinner size="md" color="text-white" />
          ) : isActive ? (
            <div className="w-8 h-8 bg-red-500 rounded-sm animate-pulse shadow-[0_0_15px_rgba(239,68,68,0.8)]"></div>
          ) : (
            <MicIcon className="w-10 h-10 text-white" />
          )}

          <div className="absolute -inset-4 bg-white/5 rounded-full scale-0 group-hover:scale-100 transition-transform duration-500" />
        </button>

        {error && (
          <div className="mt-8 bg-red-500/20 text-red-400 px-6 py-2 rounded-full text-xs font-bold tracking-wider border border-red-500/30 animate-shake">
            {error}
          </div>
        )}
      </footer>

      {/* Modal - Admin panel */}
      {isAdminOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/90 backdrop-blur-xl animate-in fade-in duration-300">
          <div className="bg-[#111] border border-white/10 rounded-[2.5rem] w-full max-w-lg p-10 shadow-2xl overflow-hidden relative">
            <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-blue-500 via-purple-500 to-pink-500 opacity-50" />

            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-bold tracking-tight">Admin Console</h2>
              <button 
                onClick={() => { setIsAdminOpen(false); setIsAdminAuthenticated(false); setAdminKeyInput(''); }}
                className="w-10 h-10 flex items-center justify-center rounded-full hover:bg-white/5 transition-all"
              >
                ✕
              </button>
            </div>

            {!isAdminAuthenticated ? (
              <form onSubmit={handleAdminAuth} className="space-y-6">
                <div>
                  <label className="block text-[10px] font-bold uppercase tracking-[0.2em] text-white/30 mb-3">Authentication</label>
                  <input 
                    type="password"
                    value={adminKeyInput}
                    onChange={(e) => setAdminKeyInput(e.target.value)}
                    placeholder="Admin password"
                    className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 focus:outline-none focus:border-blue-500/50 focus:bg-white/10 transition-all"
                    autoFocus
                  />
                </div>
                <button 
                  type="submit"
                  className="w-full bg-white text-black font-black py-4 rounded-2xl hover:bg-blue-400 transition-all hover:scale-[1.02] active:scale-[0.98] uppercase tracking-widest text-sm"
                >
                  Authorize
                </button>
              </form>
            ) : (
              <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-500">
                <div>
                  <label className="block text-[10px] font-bold uppercase tracking-[0.2em] text-white/30 mb-3">System Behavior (Roleplay)</label>
                  <textarea 
                    value={systemInstruction}
                    onChange={(e) => setSystemInstruction(e.target.value)}
                    rows={8}
                    className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-5 focus:outline-none focus:border-blue-500/50 focus:bg-white/10 transition-all text-sm leading-relaxed custom-scrollbar"
                    placeholder="Instructions for the agent..."
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-bold uppercase tracking-[0.2em] text-white/30 mb-3">Update Key</label>
                  <input 
                    type="text"
                    value={newAdminKey}
                    onChange={(e) => setNewAdminKey(e.target.value)}
                    placeholder="New admin password"
                    className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 focus:outline-none focus:border-blue-500/50 transition-all text-sm"
                  />
                </div>
                <button 
                  onClick={saveAdminSettings}
                  className="w-full bg-blue-600 text-white font-black py-5 rounded-2xl hover:bg-blue-500 transition-all shadow-xl shadow-blue-900/40 uppercase tracking-widest text-sm"
                >
                  Sync Core
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Global CSS for the Bar Animation */}
      <style>{`
        @keyframes orb-bar {
          0%, 100% { height: 10px; }
          50% { height: 60px; }
        }
        .mask-fade-top {
          -webkit-mask-image: linear-gradient(to bottom, transparent 0%, black 100%);
          mask-image: linear-gradient(to bottom, transparent 0%, black 100%);
        }
        @keyframes pulse-custom {
          0%, 100% { opacity: 0.4; transform: scale(1); }
          50% { opacity: 0.2; transform: scale(0.98); }
        }
        .animate-pulse-custom {
          animation: pulse-custom 3s infinite ease-in-out;
        }
      `}</style>
    </div>
  );
};

export default App;

