            <div className="flex justify-between items-center mb-10 text-2xl font-bold">Admin Console <button onClick={() => { setIsAdminOpen(false); setIsAdminAuthenticated(false); }} className="opacity-40">✕</button></div>
            {!isAdminAuthenticated ? (
              <form onSubmit={handleAdminAuth} className="space-y-6">
                <input type="password" value={adminKeyInput} onChange={(e) => setAdminKeyInput(e.target.value)} placeholder="Authorization Key" className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 focus:outline-none focus:border-blue-500/50" autoFocus />
                <button type="submit" className="w-full bg-white text-black font-black py-4 rounded-2xl tracking-widest uppercase text-xs">Unlock</button>
