            ) : (
              <div className="space-y-8">
                <div><label className="block text-[10px] font-bold uppercase tracking-widest text-white/30 mb-3">Core Directives (Roleplay)</label><textarea value={systemInstruction} onChange={(e) => setSystemInstruction(e.target.value)} rows={6} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 focus:outline-none text-sm" /></div>
                <div><label className="block text-[10px] font-bold uppercase tracking-widest text-white/30 mb-3">Update Key</label><input type="text" value={newAdminKey} onChange={(e) => setNewAdminKey(e.target.value)} placeholder="New Password" className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 focus:outline-none" /></div>
                <button onClick={saveAdminSettings} className="w-full bg-blue-600 text-white font-black py-5 rounded-2xl tracking-widest uppercase text-xs">Commit Changes</button>
              </div>
            )}
          </div>
        </div>
      )}

      <style>{`
        @keyframes orb-bar { 0%, 100% { height: 4px; } 50% { height: 60px; } }
        .animate-orb-bar { animation: orb-bar 0.6s infinite ease-in-out; }
        @keyframes float { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-20px); } }
        .animate-float { animation: float 6s infinite ease-in-out; }
        @keyframes pulse-slow { 0%, 100% { opacity: 0.3; transform: scale(1); } 50% { opacity: 0.15; transform: scale(1.1); } }
        .animate-pulse-slow { animation: pulse-slow 8s infinite ease-in-out; }
      `}</style>
    </div>
  );
};

