const DEFAULT_SYSTEM_INSTRUCTION = `You are an elite, hyper-responsive AI companion similar to Sesame AI. 
CRITICAL: You MUST use a hidden emotion tag at the start of your response: [USER_EMOTIONS: Emotion1: 0.xx, Emotion2: 0.xx, Emotion3: 0.xx].
IMPORTANT: Do NOT speak the tag. Do NOT say "User emotions". Immediately begin your conversational response after the tag.
Your personality is warm, witty, and extremely natural. Use filler words like "Oh!", "Mhmm", "Right", "I totally get that" to feel human. 
Keep responses very short (1-2 sentences) to maintain high-speed turn-taking. 
Respond INSTANTLY. Analyze prosody to detect subtext accurately.`;

const App: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [status, setStatus] = useState(UI_STRINGS.READY);
  const [history, setHistory] = useState<ChatTurn[]>([]);
  const [liveTranscript, setLiveTranscript] = useState({ user: '', model: '' });
  const [error, setError] = useState<string | null>(null);

  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [adminKeyInput, setAdminKeyInput] = useState('');
  const [systemInstruction, setSystemInstruction] = useState(localStorage.getItem('gemini_admin_prompt') || DEFAULT_SYSTEM_INSTRUCTION);
  const [storedAdminKey, setStoredAdminKey] = useState(localStorage.getItem('gemini_admin_key') || 'admin123');
  const [newAdminKey, setNewAdminKey] = useState('');

  const [userEmotions, setUserEmotions] = useState<Emotion[]>([]);

  const sessionRef = useRef<any>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const transcriptRef = useRef({ user: '', model: '', rawModel: '' });

  const stopAllAudio = useCallback(() => {
    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
  }, []);

  const parseEmotions = (text: string) => {
    const match = text.match(/\[USER_EMOTIONS:\s*(.*?)\]/);
    if (match) {
      const pairs = match[1].split(',').map(p => {
        const parts = p.split(':');
        if (parts.length < 2) return null;
        return { name: parts[0].trim(), score: parseFloat(parts[1].trim()) || 0 };
      }).filter(p => p !== null) as Emotion[];
      return pairs;
    }
    return null;
  };

  const connectSession = async () => {
    if (sessionRef.current) return;
    setError(null);
    setStatus(UI_STRINGS.CONNECTING);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      inputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_INPUT });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_OUTPUT });

      await inputContextRef.current.resume();
      await outputContextRef.current.resume();

      const outputNode = outputContextRef.current.createGain();
      outputNode.connect(outputContextRef.current.destination);

      const sessionPromise = ai.live.connect({
        model: GEMINI_MODEL_NAME,
        callbacks: {
          onopen: () => {
            setStatus(UI_STRINGS.LISTENING);
            setIsActive(true);
            const source = inputContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Processing transcript and emotions
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              transcriptRef.current.rawModel += text;

              // Strip emotions from view
              const cleaned = transcriptRef.current.rawModel.replace(/\[USER_EMOTIONS:.*?\]/g, '').trim();
              transcriptRef.current.model = cleaned;
              setLiveTranscript(prev => ({ ...prev, model: cleaned }));

              const emotions = parseEmotions(transcriptRef.current.rawModel);
              if (emotions) setUserEmotions(emotions);
            } else if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              transcriptRef.current.user += text;
              setLiveTranscript(prev => ({ ...prev, user: transcriptRef.current.user }));
              // Give visual cue of active hearing
              if (status !== UI_STRINGS.PROCESSING) setStatus(UI_STRINGS.LISTENING);
            }

            if (message.serverContent?.turnComplete) {
              const u = transcriptRef.current.user;
              const m = transcriptRef.current.model;
              if (u || m) {
                setHistory(prev => [
                  ...prev,
                  { id: Date.now() + '-u', role: 'user', text: u, timestamp: Date.now() },
                  { id: Date.now() + '-m', role: 'model', text: m, timestamp: Date.now() }
                ].slice(-10));
              }
              transcriptRef.current = { user: '', model: '', rawModel: '' };
              setLiveTranscript({ user: '', model: '' });
            }

            // Audio handling
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputContextRef.current) {
              setStatus(UI_STRINGS.SPEAKING);
              const now = outputContextRef.current.currentTime;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, now);

              const buffer = await decodeAudioData(decode(audioData), outputContextRef.current, AUDIO_SAMPLE_RATE_OUTPUT, 1);
              const source = outputContextRef.current.createBufferSource();
              source.buffer = buffer;
              source.connect(outputNode);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setStatus(UI_STRINGS.LISTENING);
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              stopAllAudio();
              setStatus(UI_STRINGS.LISTENING);
            }
          },
          onerror: (e) => {
            console.error("Live Error:", e);
            setError("Connection reset. Check your key.");
            disconnect();
          },
          onclose: () => disconnect()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
          systemInstruction: systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      setError(err.message || UI_STRINGS.ERROR_MIC_PERMISSION);
      setStatus(UI_STRINGS.READY);
    }
  };

  const disconnect = () => {
    if (sessionRef.current) try { sessionRef.current.close(); } catch (e) {}
    if (inputContextRef.current) inputContextRef.current.close();
    if (outputContextRef.current) outputContextRef.current.close();
    sessionRef.current = null;
    inputContextRef.current = null;
    outputContextRef.current = null;
    stopAllAudio();
    setIsActive(false);
    setUserEmotions([]);
    setLiveTranscript({ user: '', model: '' });
    setStatus(UI_STRINGS.READY);
  };

  const toggleSession = () => (isActive ? disconnect() : connectSession());

  const handleAdminAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminKeyInput === storedAdminKey) { setIsAdminAuthenticated(true); setError(null); }
    else setError("Invalid Key");
  };

  const saveAdminSettings = () => {
    localStorage.setItem('gemini_admin_prompt', systemInstruction);
    if (newAdminKey) { localStorage.setItem('gemini_admin_key', newAdminKey); setStoredAdminKey(newAdminKey); setNewAdminKey(''); }
    setIsAdminOpen(false); setIsAdminAuthenticated(false); setAdminKeyInput('');
    if (isActive) { disconnect(); setTimeout(connectSession, 300); }
  };

  const orbGlowColor = useMemo(() => {
    if (userEmotions.length === 0) return 'rgba(59,130,246,0.3)';
    const name = userEmotions[0].name.toLowerCase();
    if (name.includes('joy') || name.includes('happy')) return 'rgba(234,179,8,0.5)';
    if (name.includes('anger') || name.includes('mad')) return 'rgba(239,68,68,0.5)';
    if (name.includes('sad')) return 'rgba(37,99,235,0.5)';
    if (name.includes('fear') || name.includes('anxiety')) return 'rgba(147,51,234,0.5)';
    if (name.includes('calm') || name.includes('peace')) return 'rgba(34,197,94,0.5)';
    return 'rgba(59,130,246,0.4)';
  }, [userEmotions]);

  return (
    <div className="relative flex flex-col h-screen bg-[#020202] text-white overflow-hidden font-sans">
      {/* Dynamic Background Glow */}
      <div className="fixed inset-0 pointer-events-none transition-all duration-700">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[110vw] h-[110vw] rounded-full blur-[140px] opacity-20 transition-all duration-1000" style={{ backgroundColor: orbGlowColor }} />
      </div>

      <header className="relative z-50 p-6 flex justify-between items-center bg-black/10 backdrop-blur-xl border-b border-white/5">
        <div className="flex items-center gap-3">
          <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-blue-400 animate-pulse shadow-[0_0_8px_rgba(96,165,250,0.8)]' : 'bg-white/10'}`} />
          <h1 className="text-[10px] font-black tracking-[0.4em] uppercase opacity-40">Sesame Gemini</h1>
        </div>
        <button onClick={() => setIsAdminOpen(true)} className="p-2 opacity-20 hover:opacity-100 transition-opacity"><SettingsIcon className="w-5 h-5" /></button>
      </header>

      <main className="relative z-20 flex-grow flex flex-col items-center justify-center">
        {/* Emotion Radar (Top Right) */}
        {isActive && userEmotions.length > 0 && (
          <div className="absolute top-10 right-10 flex flex-col items-end gap-3 z-50 pointer-events-none">
            <div className="text-[9px] font-bold tracking-[0.2em] uppercase text-white/30 mb-2 px-3 py-1 bg-white/5 rounded-full border border-white/5">Prosody Monitor</div>
            {userEmotions.map((e, i) => (
              <div key={i} className="flex flex-col items-end gap-1 w-44 group animate-in slide-in-from-right-2 duration-300">
                <div className="flex justify-between w-full px-1">
                  <span className="text-[9px] font-black uppercase text-white/40">{e.name}</span>
                  <span className="text-[9px] font-mono text-white/60">{(e.score * 100).toFixed(0)}</span>
                </div>
                <div className="w-full h-1 bg-white/5 rounded-full overflow-hidden">
                  <div className="h-full transition-all duration-1000 ease-out" style={{ width: `${e.score * 100}%`, backgroundColor: orbGlowColor, opacity: 0.7 }} />
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Central Orb Experience */}
        <div className="relative flex flex-col items-center justify-center animate-float">
          <div className="relative w-72 h-72 md:w-96 md:h-96 flex items-center justify-center">
            {/* Pulsing Aura */}
            <div className="absolute inset-0 rounded-full blur-[80px] opacity-20 animate-pulse-slow" style={{ backgroundColor: orbGlowColor }} />

            {/* Orb Shell */}
            <div className={`absolute w-full h-full rounded-full border transition-all duration-1000 ${isActive ? 'border-white/10 bg-white/5 backdrop-blur-3xl shadow-[0_0_80px_rgba(255,255,255,0.03)]' : 'border-white/5 bg-transparent'}`} />

            {/* Neural Bars */}
            <div className="z-30 flex items-center justify-center gap-2 h-24">
              {isActive ? (
                [...Array(8)].map((_, i) => (
                  <div 
                    key={i} 
                    className={`w-1 rounded-full bg-white transition-all duration-200 ${status === UI_STRINGS.SPEAKING ? 'animate-orb-bar shadow-[0_0_15px_white]' : 'h-1 opacity-10'}`} 
                    style={{ animationDelay: `${i * 0.08}s`, animationDuration: `${0.5 + Math.random() * 0.3}s` }} 
                  />
                ))
              ) : <div className="text-[10px] font-black tracking-[0.5em] uppercase opacity-10 animate-pulse">Neural Standby</div>}
            </div>
          </div>

          <div className="mt-14 text-center pointer-events-none h-6 flex items-center">
            <span className="text-[10px] font-black tracking-[0.4em] uppercase opacity-20 animate-pulse">{status}</span>
          </div>
        </div>

        {/* Live Subtitles (Fading) */}
        <div className="absolute bottom-44 w-full max-w-lg px-12 pointer-events-none flex flex-col gap-5">
          {liveTranscript.user && (
            <div className="text-xs text-right text-white/30 animate-in fade-in slide-in-from-right-2 italic">"{liveTranscript.user}"</div>
          )}
          {liveTranscript.model && (
            <div className="text-sm text-left text-blue-100/90 leading-relaxed font-medium animate-in fade-in slide-in-from-left-2 backdrop-blur-sm bg-white/5 p-4 rounded-2xl border border-white/5">{liveTranscript.model}</div>
          )}
        </div>
      </main>

      {/* Control Footer */}
      <footer className="relative z-50 p-12 flex flex-col items-center pb-20">
        <button 
          onClick={toggleSession} 
          className={`relative w-24 h-24 rounded-full flex items-center justify-center transition-all duration-500 transform active:scale-90 border-4 ${
            isActive ? 'bg-red-500/10 border-red-500/40 shadow-2xl shadow-red-900/40' : 'bg-white/5 border-white/10 hover:border-white/20 hover:bg-white/10 shadow-xl'
          }`}
        >
          {status === UI_STRINGS.CONNECTING ? (
            <Spinner size="md" color="text-white" />
          ) : isActive ? (
            <div className="w-8 h-8 bg-red-500 rounded-sm animate-pulse shadow-[0_0_20px_rgba(239,68,68,0.6)]" />
          ) : (
            <MicIcon className="w-10 h-10 text-white/80" />
          )}
        </button>
        {error && (
          <div className="mt-8 px-5 py-2 bg-red-500/10 border border-red-500/20 text-red-400 text-[10px] font-black uppercase tracking-widest rounded-full animate-shake">
            {error}
          </div>
        )}
      </footer>

      {/* Admin Panel Overlay */}
      {isAdminOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/98 backdrop-blur-3xl animate-in fade-in duration-300">
          <div className="bg-[#0a0a0a] border border-white/10 rounded-[3rem] w-full max-w-lg p-12 relative overflow-hidden shadow-2xl">
            <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-blue-600 via-indigo-600 to-purple-600 opacity-50" />
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-xl font-black uppercase tracking-widest">Neural Config</h2>
              <button onClick={() => { setIsAdminOpen(false); setIsAdminAuthenticated(false); }} className="w-10 h-10 flex items-center justify-center rounded-full hover:bg-white/5 transition-colors opacity-40 hover:opacity-100">✕</button>
            </div>
            {!isAdminAuthenticated ? (
              <form onSubmit={handleAdminAuth} className="space-y-6">
                <input type="password" value={adminKeyInput} onChange={(e) => setAdminKeyInput(e.target.value)} placeholder="Auth Key" className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 focus:outline-none focus:border-blue-500/50 transition-all" autoFocus />
                <button type="submit" className="w-full bg-white text-black font-black py-5 rounded-2xl tracking-[0.2em] uppercase text-xs hover:bg-blue-400 transition-colors">Access Core</button>
              </form>
            ) : (
              <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-500">
                <div><label className="block text-[9px] font-black uppercase tracking-[0.2em] text-white/30 mb-4 px-1">Personality Directives</label><textarea value={systemInstruction} onChange={(e) => setSystemInstruction(e.target.value)} rows={7} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-5 focus:outline-none text-sm leading-relaxed custom-scrollbar" /></div>
                <div><label className="block text-[9px] font-black uppercase tracking-[0.2em] text-white/30 mb-4 px-1">Rotation Key</label><input type="text" value={newAdminKey} onChange={(e) => setNewAdminKey(e.target.value)} placeholder="New Password" className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 focus:outline-none focus:border-blue-500/50" /></div>
                <button onClick={saveAdminSettings} className="w-full bg-blue-600 text-white font-black py-5 rounded-2xl tracking-[0.2em] uppercase text-xs shadow-xl shadow-blue-900/20 hover:bg-blue-500 transition-colors">Sync Directives</button>
              </div>
            )}
          </div>
        </div>
      )}

      <style>{`
        @keyframes orb-bar { 0%, 100% { height: 6px; } 50% { height: 70px; } }
        .animate-orb-bar { animation: orb-bar 0.4s infinite ease-in-out; }
        @keyframes float { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-25px); } }
        .animate-float { animation: float 5s infinite ease-in-out; }
        @keyframes pulse-slow { 0%, 100% { opacity: 0.2; transform: scale(1); } 50% { opacity: 0.1; transform: scale(1.15); } }
        .animate-pulse-slow { animation: pulse-slow 7s infinite ease-in-out; }
        @keyframes shake { 0%, 100% { transform: translateX(0); } 25% { transform: translateX(-4px); } 75% { transform: translateX(4px); } }
        .animate-shake { animation: shake 0.3s ease-in-out; }
      `}</style>
    </div>
  );
};

