const DEFAULT_SYSTEM_INSTRUCTION = `You are an elite, hyper-responsive AI sales trainer. 
CRITICAL: You MUST prepend your response with a hidden emotion tag: [USER_EMOTIONS: Emotion1: 0.xx, Emotion2: 0.xx, Emotion3: 0.xx]. 
DO NOT SPEAK THE TAG. Do not mention the word "emotion" in your voice.
Personality: Extremely high energy, empathetic, and professional. 
Responses must be brief (under 15 words) and natural. Use "Mhmm", "Ah", "I see" to bridge turns.
Your goal is to mirror the user's energy while providing subtle coaching.`;

const App: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [status, setStatus] = useState(UI_STRINGS.READY);
  const [liveTranscript, setLiveTranscript] = useState({ user: '', model: '' });
  const [error, setError] = useState<string | null>(null);

  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [adminKeyInput, setAdminKeyInput] = useState('');
  const [systemInstruction, setSystemInstruction] = useState(localStorage.getItem('gemini_admin_prompt') || DEFAULT_SYSTEM_INSTRUCTION);
  const [storedAdminKey, setStoredAdminKey] = useState(localStorage.getItem('gemini_admin_key') || 'admin123');
  const [newAdminKey, setNewAdminKey] = useState('');

  const [userEmotions, setUserEmotions] = useState<Emotion[]>([]);

  const sessionRef = useRef<any>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const transcriptRef = useRef({ user: '', model: '', rawModel: '' });

  const stopAllAudio = useCallback(() => {
    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
  }, []);

  const parseEmotions = (text: string) => {
    const match = text.match(/\[USER_EMOTIONS:\s*(.*?)\]/);
    if (match) {
      const pairs = match[1].split(',').map(p => {
        const parts = p.split(':');
        if (parts.length < 2) return null;
        return { name: parts[0].trim(), score: parseFloat(parts[1].trim()) || 0 };
      }).filter(p => p !== null) as Emotion[];
      return pairs;
    }
    return null;
  };

  const connectSession = async () => {
    if (sessionRef.current) return;
    setError(null);
    setStatus(UI_STRINGS.CONNECTING);

    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey) throw new Error("API Key missing from environment.");

      // Initialize fresh to avoid the Alkalis 400 Network error
      const ai = new GoogleGenAI({ apiKey });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      inputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_INPUT });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_OUTPUT });

      await inputContextRef.current.resume();
      await outputContextRef.current.resume();

      const outputNode = outputContextRef.current.createGain();
      outputNode.connect(outputContextRef.current.destination);

      const sessionPromise = ai.live.connect({
        model: GEMINI_MODEL_NAME,
        callbacks: {
          onopen: () => {
            setStatus(UI_STRINGS.LISTENING);
            setIsActive(true);
            const source = inputContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob })).catch(err => {
                 console.warn("Stream send failed:", err);
              });
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              transcriptRef.current.rawModel += text;
              // Strip emotions from view transcript
              const cleaned = transcriptRef.current.rawModel.replace(/\[USER_EMOTIONS:.*?\]/g, '').trim();
              transcriptRef.current.model = cleaned;
              setLiveTranscript(prev => ({ ...prev, model: cleaned }));
              const emotions = parseEmotions(transcriptRef.current.rawModel);
              if (emotions) setUserEmotions(emotions);
            } else if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              transcriptRef.current.user += text;
              setLiveTranscript(prev => ({ ...prev, user: transcriptRef.current.user }));
              if (status !== UI_STRINGS.PROCESSING) setStatus(UI_STRINGS.LISTENING);
            }

            if (message.serverContent?.turnComplete) {
              transcriptRef.current = { user: '', model: '', rawModel: '' };
              setLiveTranscript({ user: '', model: '' });
            }

            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputContextRef.current) {
              setStatus(UI_STRINGS.SPEAKING);
              const now = outputContextRef.current.currentTime;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, now);

              const buffer = await decodeAudioData(decode(audioData), outputContextRef.current, AUDIO_SAMPLE_RATE_OUTPUT, 1);
              const source = outputContextRef.current.createBufferSource();
              source.buffer = buffer;
              source.connect(outputNode);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setStatus(UI_STRINGS.LISTENING);
              };
              // FAST SCHEDULING for low latency
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              stopAllAudio();
              setStatus(UI_STRINGS.LISTENING);
            }
          },
          onerror: (e) => {
            console.error("Live Network Error:", e);
            setError("Connection reset. Ensure the API project is active and Key is valid.");
            disconnect();
          },
          onclose: () => disconnect()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
          systemInstruction: systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error("Boot Error:", err);
      setError(err.message || UI_STRINGS.ERROR_MIC_PERMISSION);
      setStatus(UI_STRINGS.READY);
    }
  };

  const disconnect = () => {
    if (sessionRef.current) try { sessionRef.current.close(); } catch (e) {}
    if (inputContextRef.current) inputContextRef.current.close();
    if (outputContextRef.current) outputContextRef.current.close();
    sessionRef.current = null;
    inputContextRef.current = null;
    outputContextRef.current = null;
    stopAllAudio();
    setIsActive(false);
    setUserEmotions([]);
    setLiveTranscript({ user: '', model: '' });
    setStatus(UI_STRINGS.READY);
  };

  const toggleSession = () => (isActive ? disconnect() : connectSession());

  const handleAdminAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminKeyInput === storedAdminKey) { setIsAdminAuthenticated(true); setError(null); }
    else setError("Access Denied");
  };

  const saveAdminSettings = () => {
    localStorage.setItem('gemini_admin_prompt', systemInstruction);
    if (newAdminKey) { localStorage.setItem('gemini_admin_key', newAdminKey); setStoredAdminKey(newAdminKey); setNewAdminKey(''); }
    setIsAdminOpen(false); setIsAdminAuthenticated(false); setAdminKeyInput('');
    if (isActive) { disconnect(); setTimeout(connectSession, 300); }
  };

  const orbGlowColor = useMemo(() => {
    if (userEmotions.length === 0) return 'rgba(59,130,246,0.2)';
    const name = userEmotions[0].name.toLowerCase();
    if (name.includes('joy') || name.includes('happy')) return 'rgba(234,179,8,0.4)';
    if (name.includes('anger') || name.includes('mad')) return 'rgba(239,68,68,0.4)';
    if (name.includes('sad')) return 'rgba(37,99,235,0.4)';
    if (name.includes('fear') || name.includes('anxiety')) return 'rgba(147,51,234,0.4)';
    if (name.includes('calm') || name.includes('peace')) return 'rgba(34,197,94,0.4)';
    return 'rgba(59,130,246,0.3)';
  }, [userEmotions]);

  return (
    <div className="relative flex flex-col h-screen bg-[#050505] text-white overflow-hidden font-sans">
      <div className="fixed inset-0 pointer-events-none transition-all duration-700">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[120vw] h-[120vw] rounded-full blur-[160px] opacity-10 transition-all duration-1000" style={{ backgroundColor: orbGlowColor }} />
      </div>

      <header className="relative z-50 p-6 flex justify-between items-center bg-black/40 backdrop-blur-3xl border-b border-white/5">
        <div className="flex items-center gap-3">
          <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-blue-400 animate-pulse shadow-[0_0_12px_rgba(96,165,250,1)]' : 'bg-white/10'}`} />
          <h1 className="text-[10px] font-black tracking-[0.5em] uppercase opacity-30">Neural Sales Trainer</h1>
        </div>
        <button onClick={() => setIsAdminOpen(true)} className="p-2 opacity-20 hover:opacity-100 transition-opacity"><SettingsIcon className="w-5 h-5" /></button>
      </header>

      <main className="relative z-20 flex-grow flex flex-col items-center justify-center">
        {isActive && userEmotions.length > 0 && (
          <div className="absolute top-10 right-10 flex flex-col items-end gap-3 z-50 pointer-events-none">
            <div className="text-[9px] font-bold tracking-[0.3em] uppercase text-white/20 mb-2 px-4 py-1.5 bg-white/5 rounded-full border border-white/5 backdrop-blur-xl">Live Metrics</div>
            {userEmotions.map((e, i) => (
              <div key={i} className="flex flex-col items-end gap-1 w-44 animate-in slide-in-from-right-3 duration-500">
                <div className="flex justify-between w-full px-1">
                  <span className="text-[9px] font-black uppercase text-white/40">{e.name}</span>
                  <span className="text-[9px] font-mono text-white/60">{Math.round(e.score * 100)}%</span>
                </div>
                <div className="w-full h-1 bg-white/5 rounded-full overflow-hidden backdrop-blur-sm">
                  <div className="h-full transition-all duration-1000 ease-out" style={{ width: `${e.score * 100}%`, backgroundColor: orbGlowColor, opacity: 0.9 }} />
                </div>
              </div>
            ))}
          </div>
        )}

        <div className="relative flex flex-col items-center justify-center animate-float">
          <div className="relative w-72 h-72 md:w-96 md:h-96 flex items-center justify-center">
            <div className="absolute inset-0 rounded-full blur-[100px] opacity-10 animate-pulse-slow" style={{ backgroundColor: orbGlowColor }} />
            <div className={`absolute w-full h-full rounded-full border transition-all duration-1000 ${isActive ? 'border-white/10 bg-white/5 backdrop-blur-[60px] shadow-[0_0_120px_rgba(255,255,255,0.02)]' : 'border-white/5 bg-transparent'}`} />

            <div className="z-30 flex items-center justify-center gap-2.5 h-24">
              {isActive ? (
                [...Array(10)].map((_, i) => (
                  <div 
                    key={i} 
                    className={`w-1 rounded-full bg-white transition-all duration-150 ${status === UI_STRINGS.SPEAKING ? 'animate-orb-bar shadow-[0_0_20px_rgba(255,255,255,0.8)]' : 'h-1.5 opacity-10'}`} 
                    style={{ animationDelay: `${i * 0.05}s`, animationDuration: `${0.4 + Math.random() * 0.2}s` }} 
                  />
                ))
              ) : <div className="text-[10px] font-black tracking-[0.6em] uppercase opacity-5">Ready</div>}
            </div>
          </div>

          <div className="mt-16 text-center pointer-events-none h-6 flex items-center">
            <span className="text-[10px] font-black tracking-[0.5em] uppercase opacity-20 animate-pulse">{status}</span>
          </div>
        </div>

        <div className="absolute bottom-40 w-full max-w-xl px-12 pointer-events-none flex flex-col gap-6">
          {liveTranscript.user && (
            <div className="text-xs text-right text-white/20 animate-in fade-in slide-in-from-right-3 italic">"{liveTranscript.user}"</div>
          )}
          {liveTranscript.model && (
            <div className="text-sm text-left text-white/90 leading-relaxed font-semibold animate-in fade-in slide-in-from-left-3 backdrop-blur-2xl bg-white/[0.03] p-6 rounded-[2rem] border border-white/5 shadow-2xl">{liveTranscript.model}</div>
          )}
        </div>
      </main>

      <footer className="relative z-50 p-16 flex flex-col items-center pb-24">
        <button 
          onClick={toggleSession} 
          className={`relative w-24 h-24 rounded-full flex items-center justify-center transition-all duration-700 transform active:scale-95 border-2 ${
            isActive ? 'bg-red-500/5 border-red-500/20 shadow-2xl shadow-red-900/10' : 'bg-white/[0.02] border-white/5 hover:border-white/10 hover:bg-white/[0.04] shadow-xl'
          }`}
        >
          {status === UI_STRINGS.CONNECTING ? (
            <Spinner size="md" color="text-white" />
          ) : isActive ? (
            <div className="w-7 h-7 bg-red-500/80 rounded-[4px] animate-pulse shadow-[0_0_30px_rgba(239,68,68,0.4)]" />
          ) : (
            <MicIcon className="w-10 h-10 text-white/40" />
          )}
        </button>
        {error && (
          <div className="mt-10 px-6 py-2.5 bg-red-500/10 border border-red-500/10 text-red-400 text-[10px] font-black uppercase tracking-[0.3em] rounded-full animate-shake">
            {error}
          </div>
        )}
      </footer>

      {isAdminOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/95 backdrop-blur-[100px] animate-in fade-in duration-500">
          <div className="bg-[#080808] border border-white/5 rounded-[4rem] w-full max-w-lg p-14 relative overflow-hidden shadow-2xl">
            <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-blue-900 via-white/10 to-blue-900 opacity-20" />
            <div className="flex justify-between items-center mb-12">
              <h2 className="text-lg font-black uppercase tracking-[0.5em] opacity-50">Core Logic</h2>
              <button onClick={() => { setIsAdminOpen(false); setIsAdminAuthenticated(false); }} className="w-12 h-12 flex items-center justify-center rounded-full hover:bg-white/5 transition-colors opacity-20 hover:opacity-100">✕</button>
            </div>
            {!isAdminAuthenticated ? (
              <form onSubmit={handleAdminAuth} className="space-y-8">
                <input type="password" value={adminKeyInput} onChange={(e) => setAdminKeyInput(e.target.value)} placeholder="Authorization Required" className="w-full bg-white/[0.02] border border-white/5 rounded-3xl px-8 py-5 focus:outline-none focus:border-white/20 transition-all text-center tracking-[0.4em] uppercase text-xs" autoFocus />
                <button type="submit" className="w-full bg-white text-black font-black py-6 rounded-3xl tracking-[0.3em] uppercase text-xs hover:bg-blue-400 transition-colors">Authorize Access</button>
              </form>
            ) : (
              <div className="space-y-10 animate-in slide-in-from-bottom-5 duration-700">
                <div><label className="block text-[10px] font-black uppercase tracking-[0.4em] text-white/20 mb-5 px-2">Roleplay Directives</label><textarea value={systemInstruction} onChange={(e) => setSystemInstruction(e.target.value)} rows={8} className="w-full bg-white/[0.02] border border-white/5 rounded-[2.5rem] px-8 py-7 focus:outline-none text-sm leading-relaxed custom-scrollbar font-medium" /></div>
                <div><label className="block text-[10px] font-black uppercase tracking-[0.4em] text-white/20 mb-5 px-2">Security Key</label><input type="text" value={newAdminKey} onChange={(e) => setNewAdminKey(e.target.value)} placeholder="New Password" className="w-full bg-white/[0.02] border border-white/5 rounded-3xl px-8 py-5 focus:outline-none focus:border-white/20 text-sm" /></div>
                <button onClick={saveAdminSettings} className="w-full bg-blue-700 text-white font-black py-6 rounded-3xl tracking-[0.3em] uppercase text-xs shadow-2xl shadow-blue-900/40 hover:bg-blue-600 transition-colors">Commit to Neural Stack</button>
              </div>
            )}
          </div>
        </div>
      )}

      <style>{`
        @keyframes orb-bar { 0%, 100% { height: 8px; } 50% { height: 85px; } }
        .animate-orb-bar { animation: orb-bar 0.35s infinite ease-in-out; }
        @keyframes float { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-30px); } }
        .animate-float { animation: float 6s infinite ease-in-out; }
        @keyframes pulse-slow { 0%, 100% { opacity: 0.15; transform: scale(1); } 50% { opacity: 0.05; transform: scale(1.2); } }
        .animate-pulse-slow { animation: pulse-slow 9s infinite ease-in-out; }
        @keyframes shake { 0%, 100% { transform: translateX(0); } 20% { transform: translateX(-6px); } 80% { transform: translateX(6px); } }
        .animate-shake { animation: shake 0.4s ease-in-out; }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

