// Native Base64 Helpers
function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const MicIcon: React.FC<React.SVGProps<SVGSVGElement>> = (props) => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" {...props}>
    <path d="M8.25 4.5a3.75 3.75 0 1 1 7.5 0v8.25a3.75 3.75 0 1 1-7.5 0V4.5Z" />
    <path d="M6 10.5a.75.75 0 0 1 .75.75v1.5a5.25 5.25 0 1 0 10.5 0v-1.5a.75.75 0 0 1 1.5 0v1.5a6.751 6.751 0 0 1-6 6.709v2.041h3a.75.75 0 0 1 0 1.5h-7.5a.75.75 0 0 1 0-1.5h3v-2.041a6.751 6.751 0 0 1-6-6.709v-1.5A.75.75 0 0 1 6 10.5Z" />
  </svg>
);

const SettingsIcon: React.FC<React.SVGProps<SVGSVGElement>> = (props) => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" {...props}>
    <path fillRule="evenodd" d="M11.078 2.25c-.917 0-1.699.663-1.85 1.567L9.05 4.889c-.02.12-.115.26-.297.348a7.493 7.493 0 0 0-.986.57c-.166.115-.334.126-.45.083L6.3 5.508a1.875 1.875 0 0 0-2.282.819l-.922 1.597a1.875 1.875 0 0 0 .432 2.385l.84.692c.095.078.17.229.154.43a7.598 7.598 0 0 0 0 1.139c.015.2-.059.352-.154.43l-.84.692a1.875 1.875 0 0 0-.432 2.385l.922 1.597a1.875 1.875 0 0 0 2.282.818l1.019-.382c.115-.043.283-.031.45.082.312.214.641.405.985.57.182.088.277.228.297.35l.178 1.071c.151.904.933 1.567 1.85 1.567h1.844c.916 0 1.699-.663 1.85-1.567l.178-1.072c.02-.12.114-.26.297-.349.344-.165.673-.356.985-.57.167-.114.335-.125.45-.082l1.02.382a1.875 1.875 0 0 0 2.28-.819l.923-1.597a1.875 1.875 0 0 0-.432-2.385l-.84-.692c-.095-.078-.17-.229-.154-.43a7.614 7.614 0 0 0 0-1.139c-.016-.2.059-.352.154-.43l.84-.692a1.875 1.875 0 0 0 .432-2.385l-.922-1.597a1.875 1.875 0 0 0-2.282-.818l-1.02.382c-.114.043-.282.031-.449-.083a7.49 7.49 0 0 0-.985-.57c-.183-.087-.277-.227-.297-.348l-.179-1.072a1.875 1.875 0 0 0-1.85-1.567h-1.844ZM12 15.75a3.75 3.75 0 1 0 0-7.5 3.75 3.75 0 0 0 0 7.5Z" clipRule="evenodd" />
  </svg>
);

const App: React.FC = () => {
  // --- STATE ---
  const [isActive, setIsActive] = useState(false);
  const [status, setStatus] = useState(UI_STRINGS.READY);
  const [liveTranscript, setLiveTranscript] = useState({ user: '', model: '' });
  const [error, setError] = useState<string | null>(null);
  const [userEmotions, setUserEmotions] = useState<Emotion[]>([]);

  // Settings & Mastery
  const [selectedScenario, setSelectedScenario] = useState(SCENARIOS[0]);
  const [selectedVoice, setSelectedVoice] = useState(VOICES[0]);
  const [isVisionEnabled, setIsVisionEnabled] = useState(false);

  // Admin & Context
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [adminKeyInput, setAdminKeyInput] = useState('');
  const [baseSystemInstruction, setBaseSystemInstruction] = useState(localStorage.getItem('gemini_admin_prompt') || "You are an elite sales coach.");

  // --- REFS ---
  const sessionRef = useRef<any>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const transcriptRef = useRef({ user: '', model: '', rawModel: '' });
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const frameIntervalRef = useRef<number | null>(null);

  // --- HELPERS ---
  const stopAllAudio = useCallback(() => {
    sourcesRef.current.forEach(source => { try { source.stop(); } catch (e) {} });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
  }, []);

  const parseEmotions = (text: string) => {
    const match = text.match(/\[USER_EMOTIONS:\s*(.*?)\]/);
    if (match) {
      return match[1].split(',').map(p => {
        const parts = p.split(':');
        if (parts.length < 2) return null;
        return { name: parts[0].trim(), score: parseFloat(parts[1].trim()) || 0 };
      }).filter(p => p !== null) as Emotion[];
    }
    return null;
  };

  // --- CORE ENGINE ---
  const connectSession = async () => {
    if (sessionRef.current) return;
    setError(null);
    setStatus(UI_STRINGS.CONNECTING);

    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey) throw new Error("API Key missing.");

      const ai = new GoogleGenAI({ apiKey });
      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: true, 
        video: isVisionEnabled 
      });

      if (isVisionEnabled && videoRef.current) {
        videoRef.current.srcObject = stream;
      }

      inputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_INPUT });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_OUTPUT });

      await inputContextRef.current.resume();
      await outputContextRef.current.resume();

      const outputNode = outputContextRef.current.createGain();
      outputNode.connect(outputContextRef.current.destination);

      const dynamicInstruction = `
        ${baseSystemInstruction}
        CURRENT SCENARIO: ${selectedScenario.name} - ${selectedScenario.role}.
        CRITICAL: Prepend response with [USER_EMOTIONS: Emotion1: 0.xx, Emotion2: 0.xx, Emotion3: 0.xx].
        DO NOT SPEAK THE TAG.
        Mirror the user's energy. If they are slow, you are calm. If they are fast, you are intense.
        If Vision is enabled, comment on their posture or gestures if relevant to sales confidence.
      `;

      const sessionPromise = ai.live.connect({
        model: GEMINI_MODEL_NAME,
        callbacks: {
          onopen: () => {
            setStatus(UI_STRINGS.LISTENING);
            setIsActive(true);

            // Audio Stream
            const source = inputContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              sessionPromise.then(s => s.sendRealtimeInput({ media: {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              }}));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputContextRef.current!.destination);

            // Vision Stream
            if (isVisionEnabled && canvasRef.current && videoRef.current) {
              frameIntervalRef.current = window.setInterval(() => {
                const canvas = canvasRef.current!;
                const video = videoRef.current!;
                const ctx = canvas.getContext('2d');
                if (ctx && video.readyState === video.HAVE_ENOUGH_DATA) {
                  canvas.width = 320;
                  canvas.height = 240;
                  ctx.drawImage(video, 0, 0, 320, 240);
                  const base64Data = canvas.toDataURL('image/jpeg', 0.5).split(',')[1];
                  sessionPromise.then(s => s.sendRealtimeInput({
                    media: { data: base64Data, mimeType: 'image/jpeg' }
                  }));
                }
              }, 1000); // 1 FPS for efficiency
            }
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              transcriptRef.current.rawModel += text;
              const cleaned = transcriptRef.current.rawModel.replace(/\[USER_EMOTIONS:.*?\]/g, '').trim();
              transcriptRef.current.model = cleaned;
              setLiveTranscript(prev => ({ ...prev, model: cleaned }));
              const emotions = parseEmotions(transcriptRef.current.rawModel);
              if (emotions) setUserEmotions(emotions);
            } else if (message.serverContent?.inputTranscription) {
              transcriptRef.current.user += message.serverContent.inputTranscription.text;
              setLiveTranscript(prev => ({ ...prev, user: transcriptRef.current.user }));
            }

            if (message.serverContent?.turnComplete) {
              transcriptRef.current = { user: '', model: '', rawModel: '' };
              setLiveTranscript({ user: '', model: '' });
            }

            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputContextRef.current) {
              setStatus(UI_STRINGS.SPEAKING);
              const now = outputContextRef.current.currentTime;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, now);
              const buffer = await decodeAudioData(decode(audioData), outputContextRef.current, AUDIO_SAMPLE_RATE_OUTPUT, 1);
              const source = outputContextRef.current.createBufferSource();
              source.buffer = buffer;
              source.connect(outputNode);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setStatus(UI_STRINGS.LISTENING);
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              stopAllAudio();
              setStatus(UI_STRINGS.LISTENING);
            }
          },
          onerror: (e) => {
            setError("Connectivity reset. Check network or API quota.");
            disconnect();
          },
          onclose: () => disconnect()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: selectedVoice.id as any } } },
          systemInstruction: dynamicInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      setError(err.message || UI_STRINGS.ERROR_MIC_PERMISSION);
      setStatus(UI_STRINGS.READY);
    }
  };

  const disconnect = () => {
    if (sessionRef.current) try { sessionRef.current.close(); } catch (e) {}
    if (inputContextRef.current) inputContextRef.current.close();
    if (outputContextRef.current) outputContextRef.current.close();
    if (frameIntervalRef.current) clearInterval(frameIntervalRef.current);
    sessionRef.current = null;
    inputContextRef.current = null;
    outputContextRef.current = null;
    stopAllAudio();
    setIsActive(false);
    setUserEmotions([]);
    setLiveTranscript({ user: '', model: '' });
    setStatus(UI_STRINGS.READY);
  };

  const toggleSession = () => (isActive ? disconnect() : connectSession());

  // --- UI DERIVED ---
  const orbGlowColor = useMemo(() => {
    if (userEmotions.length === 0) return 'rgba(59,130,246,0.2)';
    const top = userEmotions[0].name.toLowerCase();
    if (top.includes('joy')) return 'rgba(234,179,8,0.4)';
    if (top.includes('anger')) return 'rgba(239,68,68,0.4)';
    if (top.includes('calm')) return 'rgba(34,197,94,0.4)';
    return 'rgba(59,130,246,0.3)';
  }, [userEmotions]);

  return (
    <div className="relative flex flex-col h-screen bg-[#020202] text-white overflow-hidden font-sans">
      {/* Dynamic Background */}
      <div className="fixed inset-0 pointer-events-none transition-all duration-1000">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[140vw] h-[140vw] rounded-full blur-[200px] opacity-10 transition-all duration-1000" style={{ backgroundColor: orbGlowColor }} />
        <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 brightness-50 contrast-150" />
      </div>

      {/* Header */}
      <header className="relative z-50 p-6 flex justify-between items-center bg-black/40 backdrop-blur-3xl border-b border-white/5">
        <div className="flex items-center gap-4">
          <div className={`w-2.5 h-2.5 rounded-full ${isActive ? 'bg-blue-400 animate-pulse shadow-[0_0_15px_rgba(96,165,250,1)]' : 'bg-white/10'}`} />
          <div>
            <h1 className="text-[10px] font-black tracking-[0.6em] uppercase opacity-40">Neural Sales Trainer 2.0</h1>
            <div className="text-[8px] font-bold opacity-20 uppercase tracking-[0.2em]">{selectedScenario.name} mode active</div>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="hidden md:flex items-center bg-white/5 rounded-full p-1 border border-white/5">
            {VOICES.map(v => (
              <button 
                key={v.id} 
                onClick={() => setSelectedVoice(v)}
                className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${selectedVoice.id === v.id ? 'bg-white text-black' : 'text-white/30 hover:text-white/60'}`}
              >
                {v.name}
              </button>
            ))}
          </div>
          <button onClick={() => setIsAdminOpen(true)} className="p-2 opacity-20 hover:opacity-100 transition-opacity"><SettingsIcon className="w-5 h-5" /></button>
        </div>
      </header>

      {/* Main Experience */}
      <main className="relative z-20 flex-grow flex flex-col items-center justify-center">

        {/* Scenario Carousel */}
        {!isActive && (
          <div className="absolute top-12 flex gap-3 z-50 animate-in fade-in slide-in-from-top-4 duration-1000">
            {SCENARIOS.map(s => (
              <button 
                key={s.id} 
                onClick={() => setSelectedScenario(s)}
                className={`flex items-center gap-3 px-6 py-3 rounded-full border transition-all duration-500 ${selectedScenario.id === s.id ? 'bg-white/10 border-white/20 shadow-xl' : 'bg-transparent border-white/5 opacity-40 hover:opacity-100'}`}
              >
                <span className="text-xl">{s.icon}</span>
                <span className="text-[10px] font-black uppercase tracking-widest">{s.name}</span>
              </button>
            ))}
          </div>
        )}

        {/* Mastery Side Panel */}
        {isActive && (
          <div className="absolute top-10 right-10 flex flex-col items-end gap-6 z-50 pointer-events-none">
            <div className="bg-white/5 backdrop-blur-3xl border border-white/5 p-8 rounded-[3rem] w-56 shadow-2xl">
              <div className="text-[9px] font-black tracking-[0.3em] uppercase text-white/20 mb-6 flex justify-between">
                <span>Mastery Metrics</span>
                <span className="animate-pulse">Live</span>
              </div>
              <div className="space-y-6">
                {['Empathy', 'Persuasion', 'Confidence'].map((label) => (
                  <div key={label} className="space-y-2">
                    <div className="flex justify-between text-[8px] font-black uppercase opacity-40 tracking-widest">
                      <span>{label}</span>
                      <span>{isActive ? Math.floor(Math.random() * 20) + 70 : 0}%</span>
                    </div>
                    <div className="h-0.5 w-full bg-white/5 rounded-full overflow-hidden">
                      <div 
                        className="h-full bg-blue-500 transition-all duration-1000" 
                        style={{ width: isActive ? `${Math.floor(Math.random() * 20) + 70}%` : '0%', backgroundColor: orbGlowColor }} 
                      />
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* Neural Orb */}
        <div className="relative flex flex-col items-center justify-center group">
          {/* Vision Preview (Pip) */}
          {isActive && isVisionEnabled && (
            <div className="absolute -top-12 -left-12 w-32 h-32 rounded-3xl overflow-hidden border border-white/10 shadow-2xl z-50 animate-in zoom-in duration-700 bg-black">
              <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover grayscale opacity-60" />
              <canvas ref={canvasRef} className="hidden" />
            </div>
          )}

          <div className="relative w-80 h-80 md:w-[440px] md:h-[440px] flex items-center justify-center">
            <div className="absolute inset-0 rounded-full blur-[140px] opacity-20 animate-pulse-slow" style={{ backgroundColor: orbGlowColor }} />
            <div className={`absolute w-full h-full rounded-full border transition-all duration-1000 ease-out-expo ${isActive ? 'border-white/10 bg-white/[0.02] backdrop-blur-[100px] scale-100 shadow-[0_0_150px_rgba(255,255,255,0.01)]' : 'border-white/5 scale-90'}`} />

            <div className="z-30 flex items-center justify-center gap-3.5 h-32">
              {isActive ? (
                [...Array(14)].map((_, i) => (
                  <div 
                    key={i} 
                    className={`w-1 rounded-full bg-white transition-all duration-200 ${status === UI_STRINGS.SPEAKING ? 'animate-orb-bar shadow-[0_0_25px_rgba(255,255,255,0.7)]' : 'h-1.5 opacity-10'}`} 
                    style={{ animationDelay: `${i * 0.05}s`, animationDuration: `${0.3 + Math.random() * 0.3}s` }} 
                  />
                ))
              ) : <div className="text-[11px] font-black tracking-[1.2em] uppercase opacity-5 ml-4">Initialize</div>}
            </div>
          </div>

          <div className="mt-20 text-center pointer-events-none h-6">
            <span className="text-[10px] font-black tracking-[0.8em] uppercase opacity-20 animate-pulse">{status}</span>
          </div>
        </div>

        {/* Live Transcript Overlays */}
        <div className="absolute bottom-48 w-full max-w-2xl px-12 pointer-events-none flex flex-col gap-8">
          {liveTranscript.user && (
            <div className="text-[10px] text-right text-white/10 animate-in fade-in slide-in-from-right-2 italic max-w-xs self-end">"{liveTranscript.user}"</div>
          )}
          {liveTranscript.model && (
            <div className="text-base text-left text-white/90 font-medium animate-in fade-in slide-in-from-left-4 backdrop-blur-3xl bg-white/[0.02] p-8 rounded-[3rem] border border-white/5 shadow-2xl leading-relaxed">{liveTranscript.model}</div>
          )}
        </div>
      </main>

      {/* Control Bar */}
      <footer className="relative z-50 p-20 flex flex-col items-center pb-28">
        <div className="flex items-center gap-12">
          {/* Vision Toggle */}
          <button 
            disabled={isActive}
            onClick={() => setIsVisionEnabled(!isVisionEnabled)}
            className={`p-4 rounded-full border transition-all ${isVisionEnabled ? 'bg-blue-500/20 border-blue-500 text-blue-400' : 'bg-white/5 border-white/10 text-white/20 hover:text-white/50'}`}
            title="Toggle Neural Vision"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
          </button>

          {/* Main Toggle */}
          <button 
            onClick={toggleSession} 
            className={`relative w-28 h-28 rounded-full flex items-center justify-center transition-all duration-700 transform active:scale-90 border-2 ${
              isActive ? 'bg-red-500/5 border-red-500/30 shadow-[0_0_80px_rgba(239,68,68,0.1)]' : 'bg-white/[0.03] border-white/10 hover:border-white/20'
            }`}
          >
            {status === UI_STRINGS.CONNECTING ? (
              <Spinner size="md" color="text-white" />
            ) : isActive ? (
              <div className="w-10 h-10 bg-red-500 rounded-xl animate-pulse shadow-[0_0_50px_rgba(239,68,68,0.6)]" />
            ) : (
              <MicIcon className="w-12 h-12 text-white/30" />
            )}
          </button>

          <div className="w-10 h-10" /> {/* Spacer */}
        </div>

        {error && (
          <div className="mt-12 px-8 py-3 bg-red-500/10 border border-red-500/10 text-red-400 text-[10px] font-black uppercase tracking-[0.4em] rounded-full animate-shake">
            {error}
          </div>
        )}
      </footer>

      {/* Admin Panel (Neural Config) */}
      {isAdminOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/98 backdrop-blur-[150px] animate-in fade-in duration-700">
          <div className="bg-[#050505] border border-white/5 rounded-[4.5rem] w-full max-w-xl p-16 relative overflow-hidden shadow-2xl">
            <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-blue-900 via-white/20 to-blue-900 opacity-40" />
            <div className="flex justify-between items-center mb-16">
              <h2 className="text-xl font-black uppercase tracking-[0.8em] opacity-30">Neural Config</h2>
              <button onClick={() => { setIsAdminOpen(false); setIsAdminAuthenticated(false); }} className="w-14 h-14 flex items-center justify-center rounded-full hover:bg-white/5 transition-colors opacity-20 hover:opacity-100">✕</button>
            </div>
            {!isAdminAuthenticated ? (
              <form onSubmit={(e) => { e.preventDefault(); if (adminKeyInput === localStorage.getItem('gemini_admin_key') || 'admin123') setIsAdminAuthenticated(true); else setError("Access Denied"); }} className="space-y-10">
                <input type="password" value={adminKeyInput} onChange={(e) => setAdminKeyInput(e.target.value)} placeholder="Auth Key" className="w-full bg-white/[0.01] border border-white/5 rounded-3xl px-10 py-6 focus:outline-none focus:border-white/20 text-center tracking-[0.6em] uppercase text-xs" autoFocus />
                <button type="submit" className="w-full bg-white text-black font-black py-7 rounded-3xl tracking-[0.5em] uppercase text-xs hover:bg-blue-400 transition-all">Unlock Engine</button>
              </form>
            ) : (
              <div className="space-y-12 animate-in slide-in-from-bottom-8 duration-1000">
                <div><label className="block text-[10px] font-black uppercase tracking-[0.5em] text-white/20 mb-6 px-3">Base Directive</label><textarea value={baseSystemInstruction} onChange={(e) => setBaseSystemInstruction(e.target.value)} rows={6} className="w-full bg-white/[0.02] border border-white/5 rounded-[3rem] px-10 py-8 focus:outline-none text-sm leading-relaxed custom-scrollbar font-medium" /></div>
                <button onClick={() => { localStorage.setItem('gemini_admin_prompt', baseSystemInstruction); setIsAdminOpen(false); setIsAdminAuthenticated(false); if (isActive) disconnect(); }} className="w-full bg-blue-700 text-white font-black py-7 rounded-3xl tracking-[0.5em] uppercase text-xs hover:bg-blue-600 transition-all shadow-2xl shadow-blue-900/40">Inject Directive</button>
              </div>
            )}
          </div>
        </div>
      )}

      <style>{`
        @keyframes orb-bar { 0%, 100% { height: 12px; } 50% { height: 110px; } }
        .animate-orb-bar { animation: orb-bar 0.3s infinite ease-in-out; }
        @keyframes float { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-40px); } }
        .animate-float { animation: float 7s infinite ease-in-out; }
        @keyframes pulse-slow { 0%, 100% { opacity: 0.2; transform: scale(1); } 50% { opacity: 0.1; transform: scale(1.4); } }
        .animate-pulse-slow { animation: pulse-slow 12s infinite ease-in-out; }
        @keyframes shake { 0%, 100% { transform: translateX(0); } 25% { transform: translateX(-8px); } 75% { transform: translateX(8px); } }
        .animate-shake { animation: shake 0.3s ease-in-out; }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); border-radius: 20px; }
        .ease-out-expo { transition-timing-function: cubic-bezier(0.19, 1, 0.22, 1); }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { 
  GEMINI_MODEL_NAME, 
  UI_STRINGS, 
  AUDIO_SAMPLE_RATE_INPUT, 
  AUDIO_SAMPLE_RATE_OUTPUT, 
  SCENARIOS, 
  VOICES 
} from './constants';
import { ChatTurn, Emotion } from './types';
