const NeuralOrb: React.FC<{ isActive: boolean, status: string, color: string }> = ({ isActive, status, color }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();
  const particles = useRef<any[]>([]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const initParticles = () => {
      particles.current = Array.from({ length: 40 }, () => ({
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        size: Math.random() * 2 + 1,
        angle: Math.random() * Math.PI * 2,
        speed: Math.random() * 0.5 + 0.2,
        radius: Math.random() * 100 + 50
      }));
    };

    const animate = (time: number) => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const centerX = canvas.width / 2;
      const centerY = canvas.height / 2;

      // Draw central glow
      const gradient = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, 150);
      gradient.addColorStop(0, color.replace('0.2', '0.4').replace('0.4', '0.6'));
      gradient.addColorStop(1, 'transparent');
      ctx.fillStyle = gradient;
      ctx.beginPath();
      ctx.arc(centerX, centerY, 150, 0, Math.PI * 2);
      ctx.fill();

      // Animate particles
      particles.current.forEach(p => {
        p.angle += p.speed * (isActive && status === UI_STRINGS.SPEAKING ? 2 : 1) * 0.02;
        const orbitRadius = p.radius + (isActive && status === UI_STRINGS.SPEAKING ? Math.sin(time / 100) * 20 : 0);
        const x = centerX + Math.cos(p.angle) * orbitRadius;
        const y = centerY + Math.sin(p.angle) * orbitRadius;

        ctx.fillStyle = 'rgba(255, 255, 255, 0.6)';
        ctx.beginPath();
        ctx.arc(x, y, p.size, 0, Math.PI * 2);
        ctx.fill();

        // Lines
        particles.current.forEach(p2 => {
          const dx = x - (centerX + Math.cos(p2.angle) * p2.radius);
          const dy = y - (centerY + Math.sin(p2.angle) * p2.radius);
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < 60) {
            ctx.strokeStyle = `rgba(255, 255, 255, ${0.1 * (1 - dist / 60)})`;
            ctx.lineWidth = 0.5;
            ctx.beginPath();
            ctx.moveTo(x, y);
            ctx.lineTo(centerX + Math.cos(p2.angle) * p2.radius, centerY + Math.sin(p2.angle) * p2.radius);
            ctx.stroke();
          }
        });
      });

      requestRef.current = requestAnimationFrame(animate);
    };

    initParticles();
    requestRef.current = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(requestRef.current!);
  }, [isActive, status, color]);

  return <canvas ref={canvasRef} width={600} height={600} className="w-full h-full opacity-80" />;
};

