const App: React.FC = () => {
  const [status, setStatus] = useState<string>(UI_STRINGS.READY);
  const [isConnected, setIsConnected] = useState(false);
  const [activeScenario, setActiveScenario] = useState(SCENARIOS[0]);
  const [activeVoice, setActiveVoice] = useState(VOICES[0]);
  const [showAdmin, setShowAdmin] = useState(false);
  const [report, setReport] = useState<any>(null);

  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const inputAudioContext = useRef<AudioContext | null>(null);
  const outputAudioContext = useRef<AudioContext | null>(null);
  const nextStartTime = useRef<number>(0);
  const sources = useRef<Set<AudioBufferSourceNode>>(new Set());

  const toggleSession = async () => {
    if (isConnected) {
      handleDisconnect();
      return;
    }
    await handleConnect();
  };

  const handleConnect = async () => {
    try {
      setStatus(UI_STRINGS.CONNECTING);

      // Initialize Gemini AI with API key from environment
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      inputAudioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_INPUT });
      outputAudioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_OUTPUT });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      sessionPromiseRef.current = ai.live.connect({
        model: GEMINI_MODEL_NAME,
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: activeVoice.id as any } },
          },
          systemInstruction: `You are simulating a conversation for training purposes. Scenario: ${activeScenario.name}. Role: ${activeScenario.role}. Respond naturally in character.`,
        },
        callbacks: {
          onopen: () => {
            setIsConnected(true);
            setStatus(UI_STRINGS.LISTENING);

            const source = inputAudioContext.current!.createMediaStreamSource(stream);
            const scriptProcessor = inputAudioContext.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) int16[i] = inputData[i] * 32768;

              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              sessionPromiseRef.current?.then((session) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputAudioContext.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio && outputAudioContext.current) {
              setStatus(UI_STRINGS.SPEAKING);
              const ctx = outputAudioContext.current;
              nextStartTime.current = Math.max(nextStartTime.current, ctx.currentTime);

              const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, AUDIO_SAMPLE_RATE_OUTPUT, 1);
              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(ctx.destination);
              source.onended = () => {
                sources.current.delete(source);
                if (sources.current.size === 0) setStatus(UI_STRINGS.LISTENING);
              };
              source.start(nextStartTime.current);
              nextStartTime.current += audioBuffer.duration;
              sources.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              sources.current.forEach(s => s.stop());
              sources.current.clear();
              nextStartTime.current = 0;
            }
          },
          onclose: () => {
            setIsConnected(false);
            setStatus(UI_STRINGS.READY);
          },
          onerror: (e) => {
            console.error('Session Error:', e);
            setStatus(UI_STRINGS.ERROR_CONNECTION);
          }
        }
      });
    } catch (err) {
      console.error('Connection failed:', err);
      setStatus(UI_STRINGS.ERROR_MIC_PERMISSION);
    }
  };

  const handleDisconnect = () => {
    sessionPromiseRef.current?.then(s => s.close());
    setIsConnected(false);
    setStatus(UI_STRINGS.READY);
    // Mock simulation results
    setReport({
      scores: { EQ: 88, Impact: 74, Clarity: 91 },
      feedback: `Session ended. You navigated the ${activeScenario.name} scenario with high clarity but could work on your emotional impact.`,
      strength: "Logical Consistency",
      growth: "Empathy Depth"
    });
  };

  return (
    <div className="min-h-screen bg-black text-white font-sans flex flex-col p-8 md:p-12 relative overflow-hidden">
      {/* Background glow effects */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-500/10 rounded-full blur-[120px] pointer-events-none" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-indigo-500/10 rounded-full blur-[120px] pointer-events-none" />

      {/* Header section */}
      <header className="flex justify-between items-start z-10">
        <div className="space-y-1">
          <h1 className="text-2xl font-black tracking-[0.3em] uppercase">Neural Pitch</h1>
          <div className="flex items-center gap-2">
            <span className={`w-1.5 h-1.5 rounded-full ${isConnected ? 'bg-green-500 animate-pulse' : 'bg-white/20'}`} />
            <span className="text-[10px] uppercase tracking-widest text-white/40 font-bold">{status}</span>
          </div>
        </div>

        <div className="flex gap-4">
          <button 
            onClick={() => setShowAdmin(!showAdmin)}
            className={`p-4 rounded-2xl border transition-all ${
              showAdmin ? 'bg-white text-black border-white' : 'bg-white/5 border-white/10 hover:bg-white/10'
            }`}
          >
            <SettingsIcon className="w-5 h-5" />
          </button>
        </div>
      </header>

      {/* Main visualization area */}
      <main className="flex-1 flex flex-col items-center justify-center relative py-12 md:py-20">
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <NeuralOrb isActive={isConnected} status={status} color={isConnected ? 'rgba(59, 130, 246, 0.2)' : 'rgba(255, 255, 255, 0.05)'} />
        </div>

        {showAdmin ? (
          <div className="z-10 w-full max-w-4xl">
            <AdminAnalytics />
          </div>
        ) : (
          <div className="z-10 flex flex-col items-center gap-12 text-center w-full">
            {!isConnected && (
              <div className="space-y-8 animate-in fade-in slide-in-from-top-4 duration-1000 max-w-2xl">
                <div className="space-y-3">
                  <h2 className="text-5xl md:text-7xl font-black tracking-tighter leading-tight">Master the human element.</h2>
                  <p className="text-white/40 uppercase tracking-[0.4em] text-[10px] font-bold">Simulate high-stakes business interactions with Neural AI</p>
                </div>

                <div className="flex flex-wrap justify-center gap-3">
                  {SCENARIOS.map(s => (
                    <button
                      key={s.id}
                      onClick={() => setActiveScenario(s)}
                      className={`px-6 py-3 rounded-2xl border transition-all duration-300 flex items-center gap-3 ${
                        activeScenario.id === s.id ? 'bg-white text-black border-white' : 'bg-white/5 border-white/10 text-white/60 hover:border-white/30'
                      }`}
                    >
                      <span className="text-lg">{s.icon}</span>
                      <span className="text-[10px] font-black uppercase tracking-widest">{s.name}</span>
                    </button>
                  ))}
                </div>
              </div>
            )}

            <button
              onClick={toggleSession}
              disabled={status === UI_STRINGS.CONNECTING}
              className={`group relative flex items-center justify-center w-32 h-32 md:w-40 md:h-40 rounded-full transition-all duration-500 transform active:scale-95 ${
                isConnected 
                  ? 'bg-red-500 shadow-[0_0_50px_rgba(239,68,68,0.4)] hover:bg-red-600' 
                  : 'bg-white shadow-[0_0_50px_rgba(255,255,255,0.2)] hover:scale-110'
