const App: React.FC = () => {
  const [status, setStatus] = useState<string>(UI_STRINGS.READY);
  const [isConnected, setIsConnected] = useState(false);
  const [activeScenario, setActiveScenario] = useState(SCENARIOS[0]);
  const [activeVoice, setActiveVoice] = useState(VOICES[0]);
  const [showAdmin, setShowAdmin] = useState(false);
  const [report, setReport] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Transcript tracking for AI Autopsy
  const transcriptRef = useRef<{ user: string; model: string }[]>([]);
  const currentTurnRef = useRef<{ user: string; model: string }>({ user: '', model: '' });

  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const inputAudioContext = useRef<AudioContext | null>(null);
  const outputAudioContext = useRef<AudioContext | null>(null);
  const nextStartTime = useRef<number>(0);
  const sources = useRef<Set<AudioBufferSourceNode>>(new Set());

  const auraColor = useMemo(() => {
    if (!isConnected) return 'rgba(59, 130, 246, 0.05)';
    if (status === UI_STRINGS.SPEAKING) return 'rgba(99, 102, 241, 0.3)';
    return 'rgba(59, 130, 246, 0.2)';
  }, [isConnected, status]);

  const toggleSession = async () => {
    if (isConnected) {
      handleDisconnect();
      return;
    }
    await handleConnect();
  };

  const handleConnect = async () => {
    try {
      setStatus(UI_STRINGS.CONNECTING);
      transcriptRef.current = [];
      currentTurnRef.current = { user: '', model: '' };

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      inputAudioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_INPUT });
      outputAudioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_OUTPUT });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      sessionPromiseRef.current = ai.live.connect({
        model: GEMINI_MODEL_NAME,
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: activeVoice.id as any } },
          },
          systemInstruction: `You are simulating a training conversation. Scenario: ${activeScenario.name}. Role: ${activeScenario.role}. Be authentic and challenging.`,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setIsConnected(true);
            setStatus(UI_STRINGS.LISTENING);
            const source = inputAudioContext.current!.createMediaStreamSource(stream);
            const scriptProcessor = inputAudioContext.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              sessionPromiseRef.current?.then((s) => s.sendRealtimeInput({ media: {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              }}));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputAudioContext.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Track Transcripts for Autopsy
            if (message.serverContent?.inputTranscription) {
              currentTurnRef.current.user += message.serverContent.inputTranscription.text;
            }
            if (message.serverContent?.outputTranscription) {
              currentTurnRef.current.model += message.serverContent.outputTranscription.text;
            }
            if (message.serverContent?.turnComplete) {
              transcriptRef.current.push({ ...currentTurnRef.current });
              currentTurnRef.current = { user: '', model: '' };
            }

            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio && outputAudioContext.current) {
              setStatus(UI_STRINGS.SPEAKING);
              const ctx = outputAudioContext.current;
              nextStartTime.current = Math.max(nextStartTime.current, ctx.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, AUDIO_SAMPLE_RATE_OUTPUT, 1);
              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(ctx.destination);
              source.onended = () => {
                sources.current.delete(source);
                if (sources.current.size === 0) setStatus(UI_STRINGS.LISTENING);
              };
              source.start(nextStartTime.current);
              nextStartTime.current += audioBuffer.duration;
              sources.current.add(source);
            }
            if (message.serverContent?.interrupted) {
              sources.current.forEach(s => s.stop());
              sources.current.clear();
              nextStartTime.current = 0;
            }
          },
          onclose: () => { setIsConnected(false); setStatus(UI_STRINGS.READY); },
          onerror: () => setStatus(UI_STRINGS.ERROR_CONNECTION)
        }
      });
    } catch (err) {
      setStatus(UI_STRINGS.ERROR_MIC_PERMISSION);
    }
  };

  const handleDisconnect = async () => {
    sessionPromiseRef.current?.then(s => s.close());
    setIsConnected(false);
    setStatus(UI_STRINGS.READY);

    // AI AUTOPSY - Start analysis
    if (transcriptRef.current.length > 0) {
      setIsAnalyzing(true);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const transcriptText = transcriptRef.current.map(t => `User: ${t.user}\nModel: ${t.model}`).join('\n');

        const autopsyResponse = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Analyze this sales training session. Scenario was ${activeScenario.name}. 
          Return ONLY JSON: { "scores": { "Empathy": 0-100, "Logic": 0-100, "Persistence": 0-100 }, "feedback": "Short summary", "strength": "One word", "growth": "One word" }. 
          Transcript: ${transcriptText}`,
          config: { responseMimeType: 'application/json' }
        });

        const autopsyData = JSON.parse(autopsyResponse.text || '{}');
        setReport(autopsyData);
      } catch (e) {
        console.error("Autopsy failed", e);
      } finally {
        setIsAnalyzing(false);
      }
    }
  };

  return (
    <div className="min-h-screen bg-black text-white font-sans flex flex-col p-8 md:p-12 relative overflow-hidden transition-colors duration-1000">

      {/* Background dynamic aura */}
      <div 
        className="absolute inset-0 transition-all duration-[2000ms] pointer-events-none" 
        style={{ 
          background: `radial-gradient(circle at center, ${auraColor} 0%, transparent 70%)`,
          filter: 'blur(100px)'
        }} 
      />
      <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 brightness-50 contrast-150 pointer-events-none" />

      {/* Header section */}
      <header className="flex justify-between items-start z-10">
        <div className="space-y-1">
          <h1 className="text-2xl font-black tracking-[0.4em] uppercase">Neural Pitch</h1>
          <div className="flex items-center gap-2">
            <span className={`w-1.5 h-1.5 rounded-full ${isConnected ? 'bg-blue-400 animate-pulse' : 'bg-white/10'}`} />
            <span className="text-[10px] uppercase tracking-widest text-white/40 font-bold">{status}</span>
          </div>
        </div>

        <div className="flex gap-4">
          <button 
            onClick={() => setShowAdmin(!showAdmin)}
            className={`p-4 rounded-2xl border transition-all backdrop-blur-3xl ${
              showAdmin ? 'bg-white text-black border-white' : 'bg-white/5 border-white/10 hover:bg-white/10'
            }`}
          >
            <SettingsIcon className="w-5 h-5" />
          </button>
        </div>
      </header>

      {/* Main visualization area */}
      <main className="flex-1 flex flex-col items-center justify-center relative py-12 md:py-20">

        {/* Real-time Mastery Ticker (Tesla vibe) */}
        {isConnected && (
          <div className="absolute top-0 right-0 z-50 animate-in slide-in-from-right-10 duration-1000">
            <div className="bg-white/5 backdrop-blur-3xl border border-white/10 p-6 rounded-[2.5rem] w-48 shadow-2xl">
              <div className="text-[9px] font-black tracking-[0.3em] uppercase text-white/20 mb-4">Neural Metrics</div>
              <div className="space-y-4">
                {['Confidence', 'Intensity'].map((stat) => (
                  <div key={stat} className="space-y-1.5">
                    <div className="flex justify-between text-[8px] font-bold uppercase opacity-40">
                      <span>{stat}</span>
                      <span>{Math.floor(Math.random() * 15) + 80}%</span>
                    </div>
                    <div className="h-0.5 w-full bg-white/5 rounded-full overflow-hidden">
                      <div className="h-full bg-blue-500 transition-all duration-1000" style={{ width: `${Math.floor(Math.random() * 15) + 80}%` }} />
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <NeuralOrb isActive={isConnected} status={status} color={auraColor} />
        </div>

