const NeuralOrb: React.FC<{ isActive: boolean, status: string, color: string }> = ({ isActive, status, color }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();
  const particles = useRef<any[]>([]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: true });
    if (!ctx) return;

    const initParticles = () => {
      particles.current = Array.from({ length: 60 }, () => ({
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        size: Math.random() * 1.8 + 0.4,
        angle: Math.random() * Math.PI * 2,
        speed: Math.random() * 0.25 + 0.05,
        radius: Math.random() * 130 + 40,
        opacity: Math.random() * 0.6 + 0.1
      }));
    };

    const animate = (time: number) => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const centerX = canvas.width / 2;
      const centerY = canvas.height / 2;

      const isSpeaking = status === UI_STRINGS.SPEAKING;
      const pulseSize = isSpeaking ? 180 + Math.sin(time / 80) * 25 : 150;

      const gradient = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, pulseSize);
      gradient.addColorStop(0, color);
      gradient.addColorStop(1, 'transparent');
      ctx.fillStyle = gradient;
      ctx.beginPath();
      ctx.arc(centerX, centerY, pulseSize, 0, Math.PI * 2);
      ctx.fill();

      particles.current.forEach(p => {
        const speedMult = isSpeaking ? 3.5 : 1;
        p.angle += p.speed * speedMult * 0.012;
        const orbitRadius = p.radius + (isSpeaking ? Math.sin(time / 120 + p.radius) * 35 : Math.sin(time / 700 + p.radius) * 4);
        const x = centerX + Math.cos(p.angle) * orbitRadius;
        const y = centerY + Math.sin(p.angle) * orbitRadius;

        ctx.fillStyle = `rgba(255, 255, 255, ${p.opacity})`;
        ctx.beginPath();
        ctx.arc(x, y, p.size, 0, Math.PI * 2);
        ctx.fill();

        particles.current.forEach(p2 => {
          const x2 = centerX + Math.cos(p2.angle) * p2.radius;
          const y2 = centerY + Math.sin(p2.angle) * p2.radius;
          const dx = x - x2;
          const dy = y - y2;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < 55) {
            ctx.strokeStyle = `rgba(255, 255, 255, ${0.12 * (1 - dist / 55)})`;
            ctx.lineWidth = 0.5;
            ctx.beginPath();
            ctx.moveTo(x, y);
            ctx.lineTo(x2, y2);
            ctx.stroke();
          }
        });
      });

      requestRef.current = requestAnimationFrame(animate);
    };

    initParticles();
    requestRef.current = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(requestRef.current!);
  }, [isActive, status, color]);

  return <canvas ref={canvasRef} width={600} height={600} className="w-full h-full opacity-90 transition-transform duration-1000" />;
};

