const App: React.FC = () => {
  const [status, setStatus] = useState<string>(UI_STRINGS.READY);
  const [isConnected, setIsConnected] = useState(false);
  const [activeScenario, setActiveScenario] = useState(SCENARIOS[0]);
  const [activeVoice, setActiveVoice] = useState(VOICES[0]);
  const [showAdmin, setShowAdmin] = useState(false);
  const [report, setReport] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // High-performance transcript tracking
  const transcriptRef = useRef<{ user: string; model: string }[]>([]);
  const currentTurnRef = useRef<{ user: string; model: string }>({ user: '', model: '' });

  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const inputAudioContext = useRef<AudioContext | null>(null);
  const outputAudioContext = useRef<AudioContext | null>(null);
  const nextStartTime = useRef<number>(0);
  const sources = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Apple-style dynamic background Aura
  const auraColor = useMemo(() => {
    if (!isConnected) return 'rgba(59, 130, 246, 0.03)';
    if (status === UI_STRINGS.SPEAKING) return 'rgba(99, 102, 241, 0.25)';
    if (status === UI_STRINGS.LISTENING) return 'rgba(59, 130, 246, 0.15)';
    return 'rgba(59, 130, 246, 0.1)';
  }, [isConnected, status]);

  const toggleSession = async () => {
    if (isConnected) {
      handleDisconnect();
      return;
    }
    await handleConnect();
  };

  const handleConnect = async () => {
    try {
      setStatus(UI_STRINGS.CONNECTING);
      transcriptRef.current = [];
      currentTurnRef.current = { user: '', model: '' };

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      inputAudioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_INPUT });
      outputAudioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_OUTPUT });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      sessionPromiseRef.current = ai.live.connect({
        model: GEMINI_MODEL_NAME,
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: activeVoice.id as any } },
          },
          systemInstruction: `SYSTEM DIRECTIVE: Simulate an interactive sales training scenario. 
          CUSTOMER SCENARIO: ${activeScenario.name}. ROLE: ${activeScenario.role}.
          GUIDELINE: Be highly realistic. Do not break character. Use verbal fillers if they make the character more authentic. 
          TRANSCRIPTION: Enabled for analysis.`,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setIsConnected(true);
            setStatus(UI_STRINGS.LISTENING);
            const source = inputAudioContext.current!.createMediaStreamSource(stream);
            const scriptProcessor = inputAudioContext.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              sessionPromiseRef.current?.then((s) => s.sendRealtimeInput({ media: {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              }}));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputAudioContext.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Track Transcripts for Autopsy without re-rendering
            if (message.serverContent?.inputTranscription) {
              currentTurnRef.current.user += message.serverContent.inputTranscription.text;
            }
            if (message.serverContent?.outputTranscription) {
              currentTurnRef.current.model += message.serverContent.outputTranscription.text;
            }
            if (message.serverContent?.turnComplete) {
              transcriptRef.current.push({ ...currentTurnRef.current });
              currentTurnRef.current = { user: '', model: '' };
            }

            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio && outputAudioContext.current) {
              setStatus(UI_STRINGS.SPEAKING);
              const ctx = outputAudioContext.current;
              nextStartTime.current = Math.max(nextStartTime.current, ctx.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, AUDIO_SAMPLE_RATE_OUTPUT, 1);
              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(ctx.destination);
              source.onended = () => {
                sources.current.delete(source);
                if (sources.current.size === 0) setStatus(UI_STRINGS.LISTENING);
              };
              source.start(nextStartTime.current);
              nextStartTime.current += audioBuffer.duration;
              sources.current.add(source);
            }
            if (message.serverContent?.interrupted) {
              sources.current.forEach(s => s.stop());
              sources.current.clear();
              nextStartTime.current = 0;
            }
          },
          onclose: () => { setIsConnected(false); setStatus(UI_STRINGS.READY); },
          onerror: () => setStatus(UI_STRINGS.ERROR_CONNECTION)
        }
      });
    } catch (err) {
      setStatus(UI_STRINGS.ERROR_MIC_PERMISSION);
    }
  };

  const handleDisconnect = async () => {
    sessionPromiseRef.current?.then(s => s.close());
    setIsConnected(false);
    setStatus(UI_STRINGS.READY);

    // AI AUTOPSY - Triggering scalable analysis on hangup
    if (transcriptRef.current.length > 0) {
      setIsAnalyzing(true);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const transcriptText = transcriptRef.current.map(t => `User: ${t.user}\nModel: ${t.model}`).join('\n');

        const autopsyResponse = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `TASK: Post-session autopsy. 
          CONTEXT: User practiced ${activeScenario.name} scenario.
          OUTPUT: Return JSON only.
          SCHEMA: { "scores": { "Empathy": 0-100, "Persistence": 0-100, "Logic": 0-100 }, "feedback": "string", "strength": "string", "growth": "string" }
          TRANSCRIPT: ${transcriptText}`,
          config: { responseMimeType: 'application/json' }
        });

        const autopsyData = JSON.parse(autopsyResponse.text || '{}');
        setReport(autopsyData);
      } catch (e) {
        console.error("Autopsy engine failed", e);
      } finally {
        setIsAnalyzing(false);
      }
    }
  };

  return (
    <div className="min-h-screen bg-[#020202] text-white font-sans flex flex-col p-10 md:p-16 relative overflow-hidden transition-all duration-1000">

      {/* Tesla Ticker & Background Aura */}
      <div 
        className="absolute inset-0 transition-all duration-[3000ms] pointer-events-none" 
        style={{ 
          background: `radial-gradient(circle at 50% 50%, ${auraColor} 0%, transparent 80%)`,
          filter: 'blur(120px)'
        }} 
      />
      <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 brightness-50 contrast-150 pointer-events-none mix-blend-overlay" />

      {/* Header section */}
      <header className="flex justify-between items-start z-10">
        <div className="space-y-2">
          <h1 className="text-3xl font-black tracking-[0.5em] uppercase">Neural Pitch</h1>
          <div className="flex items-center gap-3">
            <span className={`w-2 h-2 rounded-full ${isConnected ? 'bg-blue-400 animate-pulse shadow-[0_0_15px_rgba(96,165,250,0.5)]' : 'bg-white/10'}`} />
            <span className="text-[10px] uppercase tracking-[0.4em] text-white/30 font-black">{status}</span>
          </div>
        </div>

        <div className="flex gap-6">
          <button 
            onClick={() => setShowAdmin(!showAdmin)}
            className={`p-5 rounded-3xl border transition-all backdrop-blur-3xl shadow-2xl ${
              showAdmin ? 'bg-white text-black border-white' : 'bg-white/[0.02] border-white/5 hover:bg-white/[0.05] hover:border-white/20'
            }`}
          >
            <SettingsIcon className="w-6 h-6" />
          </button>
        </div>
      </header>

      {/* Main interaction field */}
      <main className="flex-1 flex flex-col items-center justify-center relative py-16 md:py-24">

        {/* Real-time Tesla-style Metrics Panel */}
        {isConnected && (
          <div className="absolute top-0 right-0 z-50 animate-in slide-in-from-right-16 duration-1000">
            <div className="bg-white/[0.01] backdrop-blur-3xl border border-white/5 p-8 rounded-[3rem] w-56 shadow-2xl">
              <div className="text-[9px] font-black tracking-[0.4em] uppercase text-white/10 mb-6">Neural Telemetry</div>
              <div className="space-y-6">
                {['Confidence', 'Presence'].map((stat) => (
                  <div key={stat} className="space-y-3">
                    <div className="flex justify-between text-[8px] font-black uppercase opacity-30 tracking-widest">
                      <span>{stat}</span>
                      <span>{Math.floor(Math.random() * 10) + 85}%</span>
                    </div>
                    <div className="h-0.5 w-full bg-white/[0.03] rounded-full overflow-hidden">
                      <div className="h-full bg-blue-500 transition-all duration-[2000ms]" style={{ width: `${Math.floor(Math.random() * 10) + 85}%` }} />
