const NeuralOrb: React.FC<{ isActive: boolean, color: string }> = ({ isActive, color }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();
  const particles = useRef<any[]>([]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const init = () => {
      particles.current = Array.from({ length: 40 }, () => ({
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        size: Math.random() * 1.5,
        angle: Math.random() * Math.PI * 2,
        speed: Math.random() * 0.02,
        radius: Math.random() * 100 + 50
      }));
    };

    const draw = (time: number) => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const cx = canvas.width / 2;
      const cy = canvas.height / 2;

      const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, isActive ? 180 : 120);
      grad.addColorStop(0, color);
      grad.addColorStop(1, 'transparent');
      ctx.fillStyle = grad;
      ctx.beginPath();
      ctx.arc(cx, cy, 200, 0, Math.PI * 2);
      ctx.fill();

      particles.current.forEach(p => {
        p.angle += p.speed * (isActive ? 4 : 1);
        const r = p.radius + (isActive ? Math.sin(time / 100) * 20 : 0);
        const x = cx + Math.cos(p.angle) * r;
        const y = cy + Math.sin(p.angle) * r;
        ctx.fillStyle = 'rgba(255,255,255,0.2)';
        ctx.beginPath();
        ctx.arc(x, y, p.size, 0, Math.PI * 2);
        ctx.fill();
      });
      requestRef.current = requestAnimationFrame(draw);
    };

    init();
    requestRef.current = requestAnimationFrame(draw);
    return () => cancelAnimationFrame(requestRef.current!);
  }, [isActive, color]);

  return <canvas ref={canvasRef} width={500} height={500} className="w-full h-full" />;
};

const App: React.FC = () => {
  const [status, setStatus] = useState<string>(UI_STRINGS.READY);
  const [isConnected, setIsConnected] = useState(false);
  const [view, setView] = useState<'home' | 'admin' | 'report'>('home');
  const [password, setPassword] = useState('');
  const [isUnlocked, setIsUnlocked] = useState(false);
  const [systemPrompt, setSystemPrompt] = useState(localStorage.getItem('neural_prompt') || DEFAULT_SYSTEM_PROMPT);
  const [reports, setReports] = useState<any[]>(JSON.parse(localStorage.getItem('neural_reports') || '[]'));
  const [currentReport, setCurrentReport] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const transcriptRef = useRef<{ user: string; model: string }[]>([]);
  const currentTurnRef = useRef<{ user: string; model: string }>({ user: '', model: '' });
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const outputAudioContext = useRef<AudioContext | null>(null);
  const nextStartTime = useRef<number>(0);
  const sources = useRef<Set<AudioBufferSourceNode>>(new Set());

  useEffect(() => {
    localStorage.setItem('neural_prompt', systemPrompt);
  }, [systemPrompt]);

  useEffect(() => {
    localStorage.setItem('neural_reports', JSON.stringify(reports));
  }, [reports]);

  const handleConnect = async () => {
    try {
      setStatus(UI_STRINGS.CONNECTING);
      transcriptRef.current = [];
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_INPUT });
      outputAudioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_OUTPUT });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      sessionPromiseRef.current = ai.live.connect({
        model: GEMINI_MODEL_NAME,
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: systemPrompt,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setIsConnected(true);
            setStatus(UI_STRINGS.LISTENING);
            const source = inputCtx.createMediaStreamSource(stream);
            const proc = inputCtx.createScriptProcessor(4096, 1, 1);
            proc.onaudioprocess = (e) => {
              const data = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(data.length);
              for (let i = 0; i < data.length; i++) int16[i] = data[i] * 32768;
              sessionPromiseRef.current?.then(s => s.sendRealtimeInput({ media: {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000'
              }}));
            };
            source.connect(proc);
            proc.connect(inputCtx.destination);
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (msg.serverContent?.inputTranscription) currentTurnRef.current.user += msg.serverContent.inputTranscription.text;
            if (msg.serverContent?.outputTranscription) currentTurnRef.current.model += msg.serverContent.outputTranscription.text;
            if (msg.serverContent?.turnComplete) {
              transcriptRef.current.push({ ...currentTurnRef.current });
              currentTurnRef.current = { user: '', model: '' };
            }

            const audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audio && outputAudioContext.current) {
              setStatus(UI_STRINGS.SPEAKING);
              const ctx = outputAudioContext.current;
              nextStartTime.current = Math.max(nextStartTime.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audio), ctx, AUDIO_SAMPLE_RATE_OUTPUT, 1);
              const src = ctx.createBufferSource();
              src.buffer = buffer;
              src.connect(ctx.destination);
              src.onended = () => {
                sources.current.delete(src);
                if (sources.current.size === 0) setStatus(UI_STRINGS.LISTENING);
              };
              src.start(nextStartTime.current);
              nextStartTime.current += buffer.duration;
              sources.current.add(src);
            }
          },
          onclose: () => { setIsConnected(false); setStatus(UI_STRINGS.READY); },
        }
      });
    } catch (e) { setStatus(UI_STRINGS.ERROR_MIC_PERMISSION); }
  };

  const handleDisconnect = async () => {
    sessionPromiseRef.current?.then(s => s.close());
    setIsConnected(false);
    setStatus(UI_STRINGS.READY);

    if (transcriptRef.current.length > 0) {
      setIsAnalyzing(true);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const text = transcriptRef.current.map(t => `U: ${t.user}\nM: ${t.model}`).join('\n');
        const res = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Analyze: ${text}. Return JSON: { "score": 0-100, "feedback": "str", "strength": "str" }`,
          config: { responseMimeType: 'application/json' }
        });
        const data = JSON.parse(res.text || '{}');
        const newReport = { ...data, timestamp: new Date().toLocaleString(), id: Date.now() };
        setReports(prev => [newReport, ...prev]);
        setCurrentReport(newReport);
        setView('report');
      } catch (e) { console.error(e); } finally { setIsAnalyzing(false); }
    }
  };

  const checkAdmin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === '2025') setIsUnlocked(true);
    else alert('Unauthorized');
  };

  return (
    <div className="min-h-screen bg-[#050505] text-white flex flex-col items-center justify-center p-6 relative overflow-hidden">

      {/* Apple-style Animated Background */}
      <div className="absolute inset-0 transition-all duration-[4000ms] pointer-events-none" 
        style={{ background: `radial-gradient(circle at 50% 50%, ${isConnected ? 'rgba(59,130,246,0.1)' : 'rgba(255,255,255,0.02)'} 0%, transparent 80%)` }} 
      />
      <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-10 pointer-events-none" />

      {/* Persistent Nav */}
      <div className="absolute top-8 left-8 right-8 flex justify-between items-center z-50">
        {view !== 'home' ? (
          <button onClick={() => setView('home')} className="p-3 bg-white/5 rounded-full border border-white/5 hover:bg-white/10 transition-all">
            <HomeIcon />
          </button>
        ) : <div />}

        <button onClick={() => setView('admin')} className="p-3 bg-white/5 rounded-full border border-white/5 hover:bg-white/10 transition-all">
          <SettingsIcon />
        </button>
      </div>

      <main className="w-full max-w-2xl flex flex-col items-center gap-12 z-10">

        {view === 'home' && (
          <>
            <div className="relative w-64 h-64 md:w-80 md:h-80 flex items-center justify-center">
              <NeuralOrb isActive={isConnected} color={isConnected ? 'rgba(59,130,246,0.4)' : 'rgba(255,255,255,0.1)'} />
            </div>

            <div className="flex flex-col items-center gap-8">
              <div className="text-center space-y-2">
                <span className="text-[10px] font-black tracking-[0.6em] text-white/20 uppercase block">{status}</span>
              </div>

              <button
                onClick={isConnected ? handleDisconnect : handleConnect}
                disabled={status === UI_STRINGS.CONNECTING || isAnalyzing}
                className={`w-24 h-24 md:w-28 md:h-28 rounded-full border-2 transition-all duration-700 flex items-center justify-center shadow-2xl transform active:scale-90 ${
                  isConnected ? 'bg-red-500/10 border-red-500/40' : 'bg-white/5 border-white/10 hover:border-white/40'
                }`}
              >
                {isAnalyzing ? <Spinner /> : isConnected ? <div className="w-6 h-6 bg-red-500 rounded-sm animate-pulse" /> : <div className="w-6 h-6 bg-white rounded-full opacity-20" />}
              </button>
            </div>
          </>
        )}

        {view === 'admin' && (
          <div className="w-full bg-white/[0.02] border border-white/5 p-10 rounded-[3rem] backdrop-blur-3xl animate-in fade-in slide-in-from-bottom-4">
            {!isUnlocked ? (
              <form onSubmit={checkAdmin} className="space-y-6">
                <h2 className="text-xs font-black tracking-[0.4em] text-white/20 uppercase text-center">Security Check</h2>
                <input 
                  type="password" 
                  value={password} 
                  onChange={e => setPassword(e.target.value)}
                  className="w-full bg-white/5 border border-white/10 p-5 rounded-2xl text-center focus:outline-none focus:border-blue-500" 
                  placeholder="PIN"
                />
                <button className="w-full bg-white text-black py-4 rounded-2xl font-black text-[10px] tracking-widest uppercase">Unlock</button>
              </form>
            ) : (
              <div className="space-y-10">
                <div className="space-y-4">
                  <h2 className="text-[10px] font-black tracking-[0.4em] text-white/20 uppercase">Neural Directives</h2>
                  <textarea 
                    value={systemPrompt}
                    onChange={e => setSystemPrompt(e.target.value)}
                    className="w-full bg-white/5 border border-white/10 p-6 rounded-3xl h-32 text-sm focus:outline-none focus:border-blue-500"
                  />
                </div>

                <div className="space-y-4">
                  <div className="flex justify-between items-center px-2">
                    <h2 className="text-[10px] font-black tracking-[0.4em] text-white/20 uppercase">Fleet Intelligence</h2>
                    <button 
                      onClick={() => {if(confirm('Wipe data?')) setReports([]);}}
                      className="text-[9px] text-red-400 font-bold uppercase tracking-widest flex items-center gap-2 hover:opacity-60"
                    >
                      <TrashIcon /> Wipe
                    </button>
                  </div>
                  <div className="max-h-60 overflow-y-auto space-y-3 custom-scrollbar">
                    {reports.length === 0 && <p className="text-[10px] text-white/10 italic p-4">No data cached.</p>}
                    {reports.map((r: any) => (
                      <div key={r.id} onClick={() => {setCurrentReport(r); setView('report');}} className="p-4 bg-white/5 border border-white/5 rounded-2xl flex justify-between items-center cursor-pointer hover:bg-white/10">
                        <div className="space-y-1">
                          <p className="text-[10px] font-bold text-white/60">{r.timestamp}</p>
                          <p className="text-xs font-black text-blue-400 uppercase tracking-widest">{r.strength}</p>
                        </div>
                        <div className="text-xl font-black text-white/20">{r.score}%</div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}
          </div>
        )}

        {view === 'report' && currentReport && (
          <div className="w-full bg-white/[0.02] border border-white/5 p-12 rounded-[4rem] backdrop-blur-3xl text-center animate-in zoom-in-95 duration-500">
            <h2 className="text-[10px] font-black tracking-[0.6em] text-white/20 uppercase mb-10">Intelligence Report</h2>
            <div className="text-8xl font-black text-blue-500 tracking-tighter mb-10">{currentReport.score}%</div>
