const NeuralOrb: React.FC<{ isActive: boolean, status: string, color: string }> = ({ isActive, status, color }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();
  const particles = useRef<any[]>([]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const init = () => {
      particles.current = Array.from({ length: 45 }, () => ({
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        size: Math.random() * 1.5 + 0.5,
        angle: Math.random() * Math.PI * 2,
        speed: Math.random() * 0.01 + 0.005,
        radius: Math.random() * 120 + 40
      }));
    };

    const draw = (time: number) => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const cx = canvas.width / 2;
      const cy = canvas.height / 2;

      const isSpeaking = status === UI_STRINGS.SPEAKING;
      const glowSize = isSpeaking ? 180 + Math.sin(time / 80) * 30 : 140;

      const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, glowSize);
      grad.addColorStop(0, color);
      grad.addColorStop(1, 'transparent');
      ctx.fillStyle = grad;
      ctx.beginPath();
      ctx.arc(cx, cy, glowSize + 50, 0, Math.PI * 2);
      ctx.fill();

      particles.current.forEach(p => {
        const speedMult = isSpeaking ? 4 : 1;
        p.angle += p.speed * speedMult;
        const orbitR = p.radius + (isSpeaking ? Math.sin(time / 150 + p.radius) * 20 : 0);
        const x = cx + Math.cos(p.angle) * orbitR;
        const y = cy + Math.sin(p.angle) * orbitR;

        ctx.fillStyle = `rgba(255, 255, 255, ${isActive ? 0.4 : 0.1})`;
        ctx.beginPath();
        ctx.arc(x, y, p.size, 0, Math.PI * 2);
        ctx.fill();
      });
      requestRef.current = requestAnimationFrame(draw);
    };

    init();
    requestRef.current = requestAnimationFrame(draw);
    return () => cancelAnimationFrame(requestRef.current!);
  }, [isActive, status, color]);

  return <canvas ref={canvasRef} width={600} height={600} className="w-full h-full opacity-80" />;
};

