import React, { useState, useEffect, useRef, useMemo } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { 
  GEMINI_MODEL_NAME, 
  UI_STRINGS, 
  AUDIO_SAMPLE_RATE_INPUT, 
  AUDIO_SAMPLE_RATE_OUTPUT, 
  DEFAULT_SYSTEM_PROMPT 
} from './constants';
