      <div className="absolute top-10 left-10 z-[100]">
        {view !== 'home' && (
          <button onClick={() => setView('home')} className="p-4 bg-gray-50 rounded-full border border-gray-100 hover:bg-gray-100 transition-all active:scale-90 shadow-sm text-[#50037F]">
            <HomeIcon />
          </button>
        )}
      </div>

      <div className="absolute top-10 right-10 z-[100]">
        <button onClick={() => setView('admin')} className="p-4 bg-gray-50 rounded-full border border-gray-100 hover:bg-gray-100 transition-all active:scale-90 shadow-sm text-[#50037F]">
          <SettingsIcon />
        </button>
      </div>

      {isConnected && (
        <div className="absolute top-32 right-10 z-[90] animate-in slide-in-from-right-10 duration-700">
          <div className="bg-white/80 backdrop-blur-xl border border-gray-100 p-8 rounded-[2.5rem] w-60 shadow-xl ring-1 ring-black/5">
            <div className="text-[9px] font-black tracking-[0.4em] uppercase text-[#50037F]/40 mb-6 px-1">Mastery Index</div>
            <div className="space-y-6">
              {[
