                  <div className="flex justify-between text-[8px] font-black uppercase tracking-widest text-gray-400">
                    <span>{s.label}</span>
                    <span className="text-[#50037F]">{Math.round(s.val)}%</span>
                  </div>
                  <div className="h-1 w-full bg-gray-100 rounded-full overflow-hidden">
                    <div className="h-full bg-[#50037F] transition-all duration-1000" style={{ width: `${s.val}%` }} />
                  </div>
