                  isConnected 
                    ? 'bg-red-50 border-red-100 shadow-lg' 
                    : 'bg-white border-gray-100 shadow-xl hover:shadow-2xl hover:border-[#50037F]/20'
                }`}
              >
                {isAnalyzing ? <Spinner size="md" color="text-[#50037F]" /> : isConnected ? <div className="w-8 h-8 bg-red-500 rounded-xl animate-pulse shadow-lg" /> : <div className="w-8 h-8 bg-[#50037F] rounded-full opacity-10 group-hover:opacity-100 transition-all duration-500" />}
