const NeuralOrb: React.FC<{ isActive: boolean, volume: number, color: string }> = ({ isActive, volume, color }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(0);
  const particles = useRef<any[]>([]);

  const volumeRef = useRef(volume);
  const activeRef = useRef(isActive);
  const colorRef = useRef(color);

  useEffect(() => {
    volumeRef.current = volume;
    activeRef.current = isActive;
    colorRef.current = color;
  }, [volume, isActive, color]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: true });
    if (!ctx) return;

    const init = () => {
      particles.current = Array.from({ length: 60 }, () => ({
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        size: Math.random() * 2 + 0.5,
        angle: Math.random() * Math.PI * 2,
        speed: Math.random() * 0.005 + 0.002,
        radius: Math.random() * 150 + 30
      }));
    };

    const draw = (time: number) => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const cx = canvas.width / 2;
      const cy = canvas.height / 2;

      const currentVolume = volumeRef.current;
      const currentActive = activeRef.current;
      const currentColor = colorRef.current;

      const glowSize = 130 + (currentVolume * 240);
      const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, glowSize);
      grad.addColorStop(0, currentColor);
      grad.addColorStop(1, 'transparent');
      ctx.fillStyle = grad;
      ctx.beginPath();
      ctx.arc(cx, cy, glowSize + 80, 0, Math.PI * 2);
      ctx.fill();

      particles.current.forEach(p => {
        p.angle += p.speed * (currentActive ? 1.5 + currentVolume * 25 : 1);
        const orbitR = p.radius + (currentActive ? Math.sin(time / 80 + p.radius) * (15 + currentVolume * 150) : 0);
        const x = cx + Math.cos(p.angle) * orbitR;
        const y = cy + Math.sin(p.angle) * orbitR;

        ctx.fillStyle = currentActive ? `rgba(80, 3, 127, ${0.4 + currentVolume})` : `rgba(80, 3, 127, 0.15)`;
        ctx.beginPath();
        ctx.arc(x, y, p.size, 0, Math.PI * 2);
        ctx.fill();
      });
      requestRef.current = requestAnimationFrame(draw);
    };

    init();
    requestRef.current = requestAnimationFrame(draw);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, []);

  return <canvas ref={canvasRef} width={600} height={600} className="w-full h-full pointer-events-none" />;
};

const App: React.FC = () => {
  const [status, setStatus] = useState<string>(UI_STRINGS.READY);
  const [isConnected, setIsConnected] = useState(false);
  const [view, setView] = useState<'home' | 'admin' | 'report'>('home');
  const [passwordInput, setPasswordInput] = useState('');
  const [storedPassword, setStoredPassword] = useState(localStorage.getItem('neural_admin_pwd') || 'admin123');
  const [isUnlocked, setIsUnlocked] = useState(false);
  const [systemPrompt, setSystemPrompt] = useState(localStorage.getItem('neural_prompt') || DEFAULT_SYSTEM_PROMPT);
  const [reports, setReports] = useState<any[]>(() => {
    const saved = JSON.parse(localStorage.getItem('neural_reports') || '[]');
    const cutoff = Date.now() - 48 * 60 * 60 * 1000;
    return saved.filter((r: any) => r.id > cutoff);
  });
  const [currentReport, setCurrentReport] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [inputVolume, setInputVolume] = useState(0);
  const [newPwdInput, setNewPwdInput] = useState('');

  const [empathy, setEmpathy] = useState(0);
  const [persuasion, setPersuasion] = useState(0);

  const transcriptRef = useRef<{ user: string; model: string }[]>([]);
  const currentTurnRef = useRef<{ user: string; model: string }>({ user: '', model: '' });
  const activeSessionRef = useRef<any>(null);
  const outputAudioContext = useRef<AudioContext | null>(null);
  const nextStartTime = useRef<number>(0);
  const sources = useRef<Set<AudioBufferSourceNode>>(new Set());

  const auraColor = useMemo(() => {
    if (!isConnected) return 'rgba(80, 3, 127, 0.02)';
    const baseOpacity = status === UI_STRINGS.SPEAKING ? 0.15 : 0.05;
    const voiceExtra = inputVolume * 0.25;
    return `rgba(80, 3, 127, ${baseOpacity + voiceExtra})`;
  }, [isConnected, status, inputVolume]);

  useEffect(() => {
    localStorage.setItem('neural_prompt', systemPrompt);
  }, [systemPrompt]);

  useEffect(() => {
    localStorage.setItem('neural_reports', JSON.stringify(reports));
  }, [reports]);

  useEffect(() => {
    localStorage.setItem('neural_admin_pwd', storedPassword);
  }, [storedPassword]);

  useEffect(() => {
    if (!isConnected) {
      setEmpathy(0);
      setPersuasion(0);
      return;
    }
    const interval = setInterval(() => {
      setEmpathy(prev => Math.min(100, Math.max(0, prev + (Math.random() * 6 - 3))));
      setPersuasion(prev => Math.min(100, Math.max(0, prev + (Math.random() * 6 - 3))));
    }, 1500);
    setEmpathy(60);
    setPersuasion(50);
    return () => clearInterval(interval);
  }, [isConnected]);

  const handleConnect = async () => {
    try {
      setStatus(UI_STRINGS.CONNECTING);
      transcriptRef.current = [];
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_INPUT });
      outputAudioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE_OUTPUT });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      // ULTRA-SNAPPY CONVERSATION PROTOCOL
      const snappinessDirective = `

      CONVERSATION PROTOCOL:
      1. RESPOND IMMEDIATELY. Aim for sub-second latency.
      2. If you need a split second to think, begin speaking instantly with a human filler like "Mm-hmm...", "I see...", "Oh...", "Right...", "Got it...".
      3. KEEP IT BRIEF. Short sentences process faster. Do not lecture.
      4. FULL DUPLEX: Interruption is natural. Stop speaking immediately if the user cuts in.
      5. BE HUMAN. Use contractions, casual phrasing, and active listening cues.
      `;

      const sessionPromise = ai.live.connect({
        model: GEMINI_MODEL_NAME,
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: systemPrompt + snappinessDirective,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setIsConnected(true);
            setStatus(UI_STRINGS.LISTENING);
            const source = inputCtx.createMediaStreamSource(stream);
            // Extreme low buffer size (512) for Hume-style responsiveness
            const proc = inputCtx.createScriptProcessor(512, 1, 1);

            proc.onaudioprocess = (e) => {
              const data = e.inputBuffer.getChannelData(0);
              let sum = 0;
              for (let i = 0; i < data.length; i++) sum += data[i] * data[i];
              const vol = Math.sqrt(sum / data.length);
              setInputVolume(vol);

              const int16 = new Int16Array(data.length);
              for (let i = 0; i < data.length; i++) int16[i] = data[i] * 32768;

              if (activeSessionRef.current) {
                activeSessionRef.current.sendRealtimeInput({ media: {
                  data: encode(new Uint8Array(int16.buffer)),
                  mimeType: 'audio/pcm;rate=16000'
                }});
              }
            };
            source.connect(proc);
            proc.connect(inputCtx.destination);

            inputCtx.resume();
            outputAudioContext.current?.resume();
          },
          onmessage: async (msg: LiveServerMessage) => {
            const interrupted = msg.serverContent?.interrupted;
            if (interrupted) {
              for (const source of sources.current.values()) {
                try { source.stop(); } catch (e) {}
                sources.current.delete(source);
              }
              nextStartTime.current = 0;
            }

            if (msg.serverContent?.inputTranscription) currentTurnRef.current.user += msg.serverContent.inputTranscription.text;
            if (msg.serverContent?.outputTranscription) currentTurnRef.current.model += msg.serverContent.outputTranscription.text;
            if (msg.serverContent?.turnComplete) {
              transcriptRef.current.push({ ...currentTurnRef.current });
              currentTurnRef.current = { user: '', model: '' };
            }

            const audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audio && outputAudioContext.current) {
              setStatus(UI_STRINGS.SPEAKING);
              const ctx = outputAudioContext.current;
              nextStartTime.current = Math.max(nextStartTime.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audio), ctx, AUDIO_SAMPLE_RATE_OUTPUT, 1);
              const src = ctx.createBufferSource();
              src.buffer = buffer;
              src.connect(ctx.destination);
              src.onended = () => {
                sources.current.delete(src);
                if (sources.current.size === 0) setStatus(UI_STRINGS.LISTENING);
              };
              src.start(nextStartTime.current);
              nextStartTime.current += buffer.duration;
              sources.current.add(src);
            }
          },
          onclose: () => { 
            setIsConnected(false); 
            setStatus(UI_STRINGS.READY); 
            setInputVolume(0);
            activeSessionRef.current = null;
          },
          onerror: (e) => {
            console.error("Link Error", e);
            setStatus(UI_STRINGS.ERROR_CONNECTION);
          }
        }
      });

      activeSessionRef.current = await sessionPromise;

    } catch (e) { 
      setStatus(UI_STRINGS.ERROR_MIC_PERMISSION); 
    }
  };

  const handleDisconnect = async () => {
    if (activeSessionRef.current) {
      activeSessionRef.current.close();
    }
    setIsConnected(false);
    setStatus(UI_STRINGS.READY);
    setInputVolume(0);

    if (transcriptRef.current.length > 0) {
      setIsAnalyzing(true);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const text = transcriptRef.current.map(t => `User: ${t.user}\nModel: ${t.model}`).join('\n');
        const res = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Coaching autopsy. Respond ONLY in JSON. { "score": 0-100, "feedback": "concise critique", "strength": "primary skill", "logic": 0-100, "empathy": 0-100 }. Transcript:\n${text}`,
          config: { responseMimeType: 'application/json' }
        });
        const autopsyData = JSON.parse(res.text || '{}');
        const finalReport = { ...autopsyData, timestamp: new Date().toLocaleString(), id: Date.now() };
        setReports(prev => [finalReport, ...prev]);
        setCurrentReport(finalReport);
        setView('report');
      } catch (e) { console.error(e); } finally { setIsAnalyzing(false); }
    }
  };

  const checkAdmin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === storedPassword) setIsUnlocked(true);
    else alert('Invalid Access Key');
  };

  const updatePassword = () => {
    if (newPwdInput.trim().length < 4) {
      alert("Password too short");
      return;
    }
    setStoredPassword(newPwdInput);
    setNewPwdInput('');
    alert("Password Updated");
  };

  return (
    <div className="min-h-screen bg-white text-gray-900 flex flex-col items-center justify-center p-6 relative overflow-hidden font-sans">
      <div className="absolute inset-0 aura-animate pointer-events-none transition-all duration-1000" 
        style={{ background: `radial-gradient(circle at 50% 50%, ${auraColor} 0%, transparent 80%)`, filter: 'blur(100px)' }} 
      />

      <div className="absolute top-10 left-10 z-[100]">
        {view !== 'home' && (
          <button onClick={() => setView('home')} className="p-4 bg-gray-50 rounded-full border border-gray-100 hover:bg-gray-200 transition-all active:scale-90 shadow-sm text-[#50037F]">
            <HomeIcon />
          </button>
        )}
      </div>

      <div className="absolute top-10 right-10 z-[100]">
        <button onClick={() => setView('admin')} className="p-4 bg-gray-50 rounded-full border border-gray-100 hover:bg-gray-200 transition-all active:scale-90 shadow-sm text-[#50037F]">
          <SettingsIcon />
        </button>
      </div>

      {isConnected && (
        <div className="absolute top-32 right-10 z-[90] animate-in slide-in-from-right-10 duration-700">
          <div className="bg-white/90 backdrop-blur-2xl border border-gray-100 p-8 rounded-[3rem] w-64 shadow-2xl ring-1 ring-black/5">
            <div className="text-[10px] font-black tracking-[0.4em] uppercase text-[#50037F]/40 mb-8 px-1">Mastery Index</div>
            <div className="space-y-8">
              {[
                { label: 'Empathy', val: empathy },
                { label: 'Persuasion', val: persuasion }
              ].map(s => (
                <div key={s.label} className="space-y-3">
                  <div className="flex justify-between text-[9px] font-black uppercase tracking-widest text-gray-400">
                    <span>{s.label}</span>
                    <span className="text-[#50037F]">{Math.round(s.val)}%</span>
                  </div>
                  <div className="h-1.5 w-full bg-gray-100 rounded-full overflow-hidden">
                    <div className="h-full bg-[#50037F] transition-all duration-1000 shadow-[0_0_10px_rgba(80,3,127,0.3)]" style={{ width: `${s.val}%` }} />
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <main className="w-full max-w-5xl flex flex-col items-center z-10">
        {view === 'home' && (
          <div className="flex flex-col items-center gap-14">
            <div className="relative w-80 h-80 md:w-[480px] md:h-[480px] flex items-center justify-center">
              <NeuralOrb isActive={isConnected} volume={inputVolume} color={isConnected ? 'rgba(80, 3, 127, 0.3)' : 'rgba(80, 3, 127, 0.05)'} />
            </div>
            <div className="flex flex-col items-center gap-12">
              <div className="text-center h-4">
                <span className="text-[11px] font-black tracking-[1em] text-[#50037F]/40 uppercase block animate-pulse">
                  {status}
                </span>
              </div>
              <button
                onClick={isConnected ? handleDisconnect : handleConnect}
                disabled={status === UI_STRINGS.CONNECTING || isAnalyzing}
                className={`group relative w-32 h-32 rounded-full border transition-all duration-1000 flex items-center justify-center transform active:scale-90 ${
                  isConnected 
                    ? 'bg-red-50 border-red-200 shadow-xl' 
                    : 'bg-white border-gray-100 shadow-2xl hover:shadow-[#50037F]/10 hover:border-[#50037F]/30'
                }`}
              >
                {isAnalyzing ? <Spinner size="lg" color="text-[#50037F]" /> : isConnected ? <div className="w-10 h-10 bg-red-600 rounded-2xl animate-pulse shadow-lg" /> : <div className="w-10 h-10 bg-[#50037F] rounded-full opacity-10 group-hover:opacity-100 transition-all duration-700" />}
                {isConnected && <div className="absolute inset-0 rounded-full border border-red-600/10 scale-150 animate-ping opacity-20" />}
              </button>
            </div>
          </div>
        )}

        {view === 'admin' && (
          <div className="w-full max-w-2xl bg-white border border-gray-100 p-16 rounded-[4.5rem] shadow-2xl animate-in fade-in slide-in-from-bottom-12 max-h-[85vh] overflow-y-auto custom-scrollbar">
            {!isUnlocked ? (
              <form onSubmit={checkAdmin} className="space-y-12 py-10 text-center">
                <h2 className="text-[11px] font-black tracking-[0.6em] text-[#50037F]/40 uppercase">Identity Access Required</h2>
                <input 
                  type="password" 
                  autoFocus
                  value={passwordInput} 
                  onChange={e => setPasswordInput(e.target.value)}
                  className="w-full bg-gray-50 border border-gray-100 p-8 rounded-3xl text-center text-3xl tracking-[0.5em] focus:outline-none focus:border-[#50037F] transition-all placeholder:opacity-20 text-[#50037F]" 
                  placeholder="••••••••"
                />
                <button className="w-full bg-[#50037F] text-white py-6 rounded-3xl font-black text-xs tracking-[0.6em] uppercase hover:opacity-90 transition-all shadow-xl active:scale-95">Unlock Command</button>
              </form>
            ) : (
              <div className="space-y-16">
                <div className="space-y-6">
                  <h2 className="text-[11px] font-black tracking-[0.5em] text-[#50037F]/40 uppercase px-4">Neural Directives</h2>
                  <textarea 
                    value={systemPrompt}
                    onChange={e => setSystemPrompt(e.target.value)}
                    className="w-full bg-gray-50 border border-gray-100 p-10 rounded-[3rem] h-56 text-sm leading-relaxed focus:outline-none focus:border-[#50037F] transition-all outline-none shadow-sm"
                    placeholder="Instructions for the AI model..."
                  />
                </div>

                <div className="space-y-6">
                  <h2 className="text-[11px] font-black tracking-[0.5em] text-[#50037F]/40 uppercase px-4">Access Control</h2>
                  <div className="flex gap-4 p-2">
                    <input 
                      type="text" 
                      value={newPwdInput} 
                      onChange={e => setNewPwdInput(e.target.value)}
