  const totalCostEstimate = useMemo(() => reports.reduce((acc, r) => acc + (r.costEstimate || 0), 0).toFixed(4), [reports]);

  // Unified Autopsy Generator
  const runAutopsyAnalysis = async () => {
    if (isProcessingAutopsy.current) return;
    const finalTranscript = transcriptRef.current;
    if (finalTranscript.length === 0 && currentTurnRef.current.user.length < 5) return;
    isProcessingAutopsy.current = true; setIsAnalyzing(true);

    try {
      const durationSec = (Date.now() - sessionStartTime.current) / 1000;
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const fullText = finalTranscript.map(t => `User: ${t.user}\nModel: ${t.model}`).join('\n') + `\nUser: ${currentTurnRef.current.user}\nModel: ${currentTurnRef.current.model}`;

      const totalTokens = (durationSec * TOKENS_PER_SEC_AUDIO) + (fullText.length * TOKENS_PER_CHAR_TEXT);
      const costEstimate = (totalTokens / 1_000_000) * ((COST_PER_1M_INPUT + COST_PER_1M_OUTPUT) / 2);

      const res = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
