      });

      const autopsyData = JSON.parse(res.text || '{}');
      const finalReport = { ...autopsyData, timestamp: new Date().toLocaleString(), id: Date.now(), userName: userName || 'Anonymous', costEstimate, tokens: Math.round(totalTokens) };
      setReports(prev => [finalReport, ...prev]); setCurrentReport(finalReport); setView('report');
      transcriptRef.current = []; currentTurnRef.current = { user: '', model: '' };
    } catch (e) { console.error(e); } finally { setIsAnalyzing(false); isProcessingAutopsy.current = false; }
  };

  const initiateNeuralLink = async (stream: MediaStream) => {
