const COST_PER_1M_INPUT = 0.10;
const COST_PER_1M_OUTPUT = 0.40;
const TOKENS_PER_SEC_AUDIO = 200; 
const TOKENS_PER_CHAR_TEXT = 0.25;

// --- UTILS ---
function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) binary += String.fromCharCode(bytes[i]);
  return btoa(binary);
}

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
  return bytes;
}

// Robust downsampling to 16kHz for AI compatibility
function downsampleTo16k(audioData: Float32Array, sampleRate: number): Int16Array {
  const targetRate = 16000;
  if (sampleRate === targetRate) {
    const int16 = new Int16Array(audioData.length);
    for (let i = 0; i < audioData.length; i++) int16[i] = audioData[i] * 32767;
    return int16;
  }
  const ratio = sampleRate / targetRate;
  const newLength = Math.floor(audioData.length / ratio);
  const int16 = new Int16Array(newLength);
  for (let i = 0; i < newLength; i++) {
    const start = Math.floor(i * ratio);
    // Simple decimation is usually sufficient for VAD/Speech
    int16[i] = audioData[start] * 32767;
  }
  return int16;
}

async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

