        model: GEMINI_MODEL_NAME,
        config: {
          responseModalities: [Modality.TEXT], // Only need transcription here
          inputAudioTranscription: { enableAutomaticPunctuation: true },
        },
        callbacks: {
          onopen: () => {
            console.log("Attestation Live session opened.");
            const source = tempInputCtx.createMediaStreamSource(pendingStream!);
            const proc = tempInputCtx.createScriptProcessor(2048, 1, 1);
            proc.onaudioprocess = (e) => {
              // console.log("Attestation onaudioprocess firing."); // Debugging
              const data = e.inputBuffer.getChannelData(0);
              const int16 = downsampleTo16k(data, actualSampleRate); // Downsample
              attestationSessionPromise.then((session) => {
                // console.log("Sending attestation audio chunk."); // Debugging
                session.sendRealtimeInput({
                  media: {
                    data: encode(new Uint8Array(int16.buffer)),
                    mimeType: 'audio/pcm;rate=16000' // Forced 16kHz
                  }
                });
              });
            };
            source.connect(proc);
            proc.connect(tempInputCtx.destination);
            tempInputCtx.resume();

            // Start timeout *after* session is open and ready to receive audio
            timeoutId = setTimeout(() => {
              if (!attestationFound && attestationSessionRef.current) {
                console.warn("Attestation timed out.");
                attestationSessionRef.current.close();
              }
            }, 15000); // Increased to 15 seconds
          },
          onmessage: (msg: LiveServerMessage) => {
            if (msg.serverContent?.inputTranscription?.text) {
              const newText = msg.serverContent.inputTranscription.text;
              currentAttestationText += newText;
              setUserAttestationTranscription(currentAttestationText.slice(-100)); // Show latest part

              // Check for "I agree" - ensure it's recent in the transcription
              const lowerText = currentAttestationText.toLowerCase();
              if (lowerText.includes("i agree") && (lowerText.length - lowerText.lastIndexOf("i agree") < 20)) { // "i agree" appears recently
                attestationFound = true;
                attestationSessionRef.current?.close(); // Close session once phrase found
              }
            }
          },
          onclose: () => {
            console.log("Attestation Live session closed. Success:", attestationFound);
            if (timeoutId) clearTimeout(timeoutId); // Clear timeout on explicit close
            tempInputCtx.close();
            setIsListeningForAttestation(false);
            setAttestationSuccess(attestationFound);
            attestationSessionRef.current = null;
          },
          onerror: (e: ErrorEvent) => {
            console.error("Attestation Live API error:", e);
            if (timeoutId) clearTimeout(timeoutId); // Clear timeout on error
            tempInputCtx.close();
            setIsListeningForAttestation(false);
            setAttestationSuccess(false);
            attestationSessionRef.current = null;
          },
        }
      });
      attestationSessionRef.current = await attestationSessionPromise;
      // Removed the initial setTimeout here, moved it to onopen callback to ensure setup is complete.

    } catch (error) {
      console.error("Error starting attestation listening:", error);
      setIsListeningForAttestation(false);
      setAttestationSuccess(false);
    }
  };

  // Effect to generate attestation audio when disclaimer is shown
  useEffect(() => {
    if (showDisclaimer && !attestationAudioUrl && !isAttestationAudioLoading) {
      generateAttestationAudio();
    }
    // Clean up temporary attestation session if disclaimer is closed
    if (!showDisclaimer && attestationSessionRef.current) {
